import { css } from "glamor"
import React from "react"
import { onHover } from "../composables/Shared"

const VERSION : string = '1.0.4'

export const getDropShadowStyle = ( props ?: { 
    opacity ?: number, 
    hover ?: number, 
    invert ?: boolean, 
    transition ?: any, 
}) => ({
    transition : props?.transition ?? undefined,
    filter: props?.invert 
        ? `drop-shadow(0 0.2rem 0.25rem rgba(0, 0, 0, ${props?.opacity !== undefined ? props.opacity : 0.2}))` 
        : `drop-shadow( 0.2rem 0 0.25rem rgba(0, 0, 0, ${props?.opacity !== undefined ? props.opacity : 0.2}))`, 
    ...( props?.hover ? {
        [onHover] : {
            filter: props?.invert 
            ? `drop-shadow(0 0.2rem 0.25rem rgba(0, 0, 0, ${props?.hover !== undefined ? props.hover : 0.2}))` 
            : `drop-shadow( 0.2rem 0 0.25rem rgba(0, 0, 0, ${props?.hover !== undefined ? props.hover : 0.2}))`, 
        }
    } : {}),
})

export default ( props : { none ?: boolean, transition ?: any,invert ?: boolean, hover ?: boolean, children ?: any, style ?: any, opacity ?: number, opacityOnHover ?: number  } ) => {

    const opacity : number = props.opacity !== undefined ? props.opacity : 0.2
    const opacityOnHover : number = props.opacityOnHover !== undefined ? props.opacityOnHover : 0.35

    // optimization -> reduce javascript usage as much as possible. Only use non-css when necessary
    if(props.hover || props.opacityOnHover !== undefined ) return (
        <div {...css({
            verticalAlign : 'top',
            width : '100%',
            display : 'inline-block',
            transition : props.transition ?? undefined,
            filter: props?.none === true ? undefined : !props.invert 
                ? `drop-shadow(0 0.2rem 0.25rem rgba(0, 0, 0, ${opacity}))` 
                : `drop-shadow( 0.2rem 0 0.25rem rgba(0, 0, 0, ${opacity}))`, 
            [onHover] : {
                filter: props?.none === true ? undefined : !props.invert 
                ? `drop-shadow(0 0.2rem 0.25rem rgba(0, 0, 0, ${opacityOnHover}))` 
                : `drop-shadow( 0.2rem 0 0.25rem rgba(0, 0, 0, ${opacityOnHover}))`, 
            },
            ...props.style
        })}>
            {props.children}
        </div>
    )


    return (<div style={{
        verticalAlign : 'top',
        width : '100%',
        display : 'inline-block',
        transition : props.transition ?? undefined,
        filter: props?.none === true ? undefined : !props.invert 
            ? `drop-shadow(0 0.2rem 0.25rem rgba(0, 0, 0, ${opacity}))` 
            : `drop-shadow( 0.2rem 0 0.25rem rgba(0, 0, 0, ${opacity}))`, 
        ...props.style
    }}>
        {props.children}
    </div>)
}