export const HeroBusBasicAndCarousel = (props: {
  static?: boolean;
  facebook?: string;
  yelp?: string;
  google?: string;
  images?: any[];
  color?: string;
  onLead?: () => void;
  children?: any;
  height?: number;
  delay?: number;
}) => {
  const [isStatic, setIsStatic] = useState(
    props.delay !== undefined ? true : props.static ? true : false
  );

  useEffect(() => {
    if (props.delay !== undefined)
      setTimeout(() => {
        setIsStatic(false);
      }, props.delay);
  }, []);

  const images: any[] = props.images
    ? props.images
    : [getImagePlaceholder(), getImagePlaceholder(), getImagePlaceholder()];

  const slideProps = {
    duration: 4000,
    transitionDuration: 600,
    autoplay: true,
    //fade : true,
    canSwipe: true,
    //arrows: false,
    infinite: true,
    easing: "ease",
    pauseOnHover: false,
    //indicators: (i) => <div className="indicator">{i + 1}</div>
    //prevArrow: <button style={{ ...buttonStyleLeft }}><div style={{ marginLeft : 20, width : 40, height : 40 }}><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="#fff"><path d="M18.464 2.114a.998.998 0 0 0-1.033.063l-13 9a1.003 1.003 0 0 0 0 1.645l13 9A1 1 0 0 0 19 21V3a1 1 0 0 0-.536-.886zM17 19.091 6.757 12 17 4.909v14.182z"></path></svg></div></button>,
    //nextArrow: <button style={{ ...buttonStyleRight }}><div style={{ marginLeft : 20, width : 40, height : 40 }}><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="#fff"><path d="M5.536 21.886a1.004 1.004 0 0 0 1.033-.064l13-9a1 1 0 0 0 0-1.644l-13-9A.998.998 0 0 0 5 3v18a1 1 0 0 0 .536.886zM7 4.909 17.243 12 7 19.091V4.909z"></path></svg></div></button>
    prevArrow: <></>,
    nextArrow: <></>,
  };

  const height: number = props.height ? props.height : 600;

  return (
    <div>
      <div style={{ height: height, width: "100%", backgroundColor: "" }}>
        <div
          className="slide-container"
          style={{}}>
          {!isStatic ? (
            <>
              <Slide {...slideProps}>
                {images.map((image: any) => {
                  return (
                    <div
                      {...css({
                        height: height,
                        width: "100%",
                        backgroundColor: "",
                        backgroundSize: "100%",
                        backgroundPosition: "center",
                        backgroundImage: `url(${image.url})`,
                        backgroundRepeat: "no-repeat",
                        ...image.style,
                      })}
                    />
                  );
                })}
              </Slide>
            </>
          ) : (
            <>
              <div
                {...css({
                  height: height,
                  width: "100%",
                  backgroundColor: "",
                  backgroundSize: "100%",
                  backgroundPosition: "center",
                  backgroundImage: `url(${images?.[0].url})`,
                  backgroundRepeat: "no-repeat",
                  ...images?.[0].style,
                })}
              />
            </>
          )}
        </div>
      </div>
      <div
        style={{
          backgroundColor: "",
          width: "100%",
          height: height,
          marginTop: -height,
          position: "absolute",
        }}>
        {props.children}
      </div>
    </div>
  );
};

