import React from "react"
import FiveStarFacebook from "./FiveStarFacebook"
import FiveStarYelp from "./FiveStarYelp"
import FiveStarGoogle from "./FiveStarGoogle"
import Hide from "../../composables/Hide"

const VERSION : number = 2

export default ( props : { gap ?: number, column ?: boolean, mobile ?: boolean }) => 
    <FiveStarGFY {...props}/>

const FiveStarGFY = ( props : { 
    gap ?: number, 
    column ?: boolean, 
    mobile ?: boolean 
    google ?: string, 
    yelp ?: string, 
    facebook?: string, 

}) => {

    const gap : number = props.gap !== undefined ? props.gap : 10
    const rowOrColumn : any = props.column ? { display : 'block'} : {}
    const responsive : any = props.mobile ? { width : 90 } : {}

    const first : any = { 
        marginRight : props.column ? 0 : gap, 
        marginBottom : props.column ? gap : 0, 
        ...rowOrColumn,
        ...responsive,
    }
    const second : any = { 
        marginLeft : props.column ? 0 : gap, 
        marginRight : props.column ? 0 : gap, 
        marginBottom : props.column ? gap : 0, 
        marginTop : props.column ? gap : 0, 
        ...rowOrColumn,
        ...responsive,
    }

    const third : any = { 
        marginLeft : props.column ? 0 : gap, 
        marginTop : props.column ? gap : 0, 
        ...rowOrColumn,
        ...responsive,
    }

    return (
        <>  
            { props.facebook    !== undefined && <FiveStarFacebook  {...{ link : props.facebook, style : first }}/> }
            { props.yelp        !== undefined && <FiveStarYelp      {...{ link : props.yelp,style : second }}/> }
            { props.google      !== undefined && <FiveStarGoogle    {...{ link : props.google, style : third }}/> }
        </>
    )
}

export const FiveStarGFYRsp = (props : { 
    facebook ?: string, 
    yelp ?: string, 
    google ?: string, 
    gap ?: number, column ?: boolean, mobile ?: boolean, breakpoint ?: number  
}) => {
    const breakpoint : number = props.breakpoint ? props.breakpoint  : 400 
    return (
        <>
            <Hide on={ breakpoint }>
                <FiveStarGFY {...props}/>
            </Hide>
            <Hide b4={ breakpoint }>
                <FiveStarGFY {...props} mobile/>
            </Hide>
        </>
    )

}