import React from "react"

const VERSION : string = '1.0.1'

export default ( props : { 
    p ?: number | string, 
    l ?: number | string,
    r ?: number | string,
    t ?: number | string,
    b ?: number | string,
    children ?: any, 
    style ?: any  
}) => {

    return <div style={{ 
        padding: props.p !== undefined ? props.p : 20, 
        ...( props.l !== undefined ? { paddingLeft: props.l } : {}),
        ...( props.r !== undefined  ? { paddingRight: props.r } : {}),
        ...( props.b !== undefined  ? { paddingBottom: props.b } : {}),
        ...( props.t !== undefined  ? { paddingTop: props.t } : {}),
        ...props.style }}>
            {props.children}
    </div>
}