import React from "react"
import YelpFiveStarReview from './five-star-yelp.svg'
import { navigate } from "gatsby"

const VERSION : number = 2
export default ( props : { style ?: any, link ?: string }) => {
    return (
        <div onClick={()=>props.link && navigate(props.link)} style={{
            cursor : props.link ? 'pointer' : 'arrow',
            display : 'inline-block',
            width: 112,
            height: 45,
            filter: 'drop-shadow(0px 4px 4px rgba(0, 0, 0, 0.25))',
            borderRadius: 10,
            backgroundImage: `url(${YelpFiveStarReview})`,
            backgroundRepeat : 'no-repeat',
            backgroundPosition : 'center',
            backgroundColor : 'white',
            ...props.style
        }}>
        </div>
    )
    
}