import React from "react"
import Hide from "../../locust/composables/Hide"
import Padding from "../../locust/composables/Padding"
import X from "../../locust/composables/X"
import { Center } from "../../locust/composables/Center"
import SpacerV from "../../locust/composables/SpacerV"
import { CircleLeftToTop } from "./CircleLeftToTop"
import { RectangleIconTitleSubtitle } from "./RectangleIconTitleSubtitle"
import { getGradientOrFallbackBackground } from "../../locust/shared/shared"

export default ( props : {
    fade ?: boolean, 
    content ?: any, 
    version ?: 1 | 2
    items : {
        color ?: string,
        icon ?: any,
        title : any, 
        subtitle : any, 
    }[],
}) => props?.version && props?.version === 2 ? <SixFeaturesBulletsV2 {...props}/> : <SixFeaturesBulletsV1 {...props}/>

export const SixFeaturesBulletsV1 = ( props : {
    fade ?: boolean, 
    content ?: any, 
    items : {
        color ?: string,
        icon ?: any,
        title : any, 
        subtitle : any, 
    }[],
}) => {

    const length : number = props.items.length


    const getProps = ( index : number, valueOverride ?: number  ) => ({
        ...props.items[ index ],
        fade : valueOverride && valueOverride === -1 ? undefined : props.fade ? 300 * (valueOverride ? valueOverride : index) : undefined,
        theme : props.content?.sections?.features?.theme,
    })
    

    return (
        <>
            <Hide on={900}>
                <Padding p={0} l={40} r={40}>
                    <X align='space-between'>
                        { length > 0  && <CircleLeftToTop {...getProps(0)}/> } 
                        { length > 1  && <CircleLeftToTop {...getProps(1)}/> } 
                        { length > 2  && <CircleLeftToTop {...getProps(2)}/> } 
                    </X>
                    <SpacerV h={70}/>
                    <X align='space-between'>
                        { length > 0  && <CircleLeftToTop {...getProps(3)}/> } 
                        { length > 1  && <CircleLeftToTop {...getProps(4)}/> } 
                        { length > 2  && <CircleLeftToTop {...getProps(5)}/> } 
                    </X>
                </Padding>
            </Hide>
            <Hide b4={900}  on={600}>
                <Center>
                    <div style={{ width : 550, display : 'inline-block'}}>
                        <X align='space-between'>
                            { length > 0  && <CircleLeftToTop {...getProps(0)}/> } 
                            { length > 1  && <CircleLeftToTop {...getProps(1)}/> } 
                        </X>
                        <SpacerV h={70}/>
                        <X align='space-between'>
                            { length > 2  && <CircleLeftToTop {...getProps(2)}/> } 
                            { length > 3  && <CircleLeftToTop {...getProps(3)}/> } 
                        </X>
                        <SpacerV h={70}/>
                        <X align='space-between'>
                            { length > 4  && <CircleLeftToTop {...getProps(4)}/> } 
                            { length > 5  && <CircleLeftToTop {...getProps(5)}/> } 
                        </X>
                    </div>
                </Center>
            </Hide>
            <Hide b4={600}>
                <Center>
                    <div style={{ maxWidth : 350, display : 'inline-block'}}>
                        { length > 0  && <CircleLeftToTop {...getProps(0,0)}/> } 
                        { length > 1  && <CircleLeftToTop {...getProps(1,0)}/> } 
                        { length > 2  && <CircleLeftToTop {...getProps(2,1)}/> }  
                        { length > 3  && <CircleLeftToTop {...getProps(3,1)}/> } 
                        { length > 4  && <CircleLeftToTop {...getProps(4,2)}/> } 
                        { length > 5  && <CircleLeftToTop {...getProps(5,2)}/> } 
                    </div>
                </Center>
            </Hide>
        </>
    )
}



