import React from "react";
import Padding from "../../../locust/composables/Padding";
import Hide, { on } from "../../../locust/composables/Hide";
import { Zoom } from "react-reveal";
import {
  PoppinsDarkAndBlueFontTextI,
  PoppinsFontII,
} from "../../../locust/font-sets/PoppinsDarkAndBlue";
import SpacerV from "../../../locust/composables/SpacerV";
import { getImagePlaceholder } from "../../shared/util";
import { onHover } from "../../../locust/composables/Shared";
import { css } from "glamor";
import { getDropShadowStyle } from "../../../locust/components/DropShadow";

export default (props: {
  version?: number;
  rgbFragment: string;
  opacity?: number;
  items?: {
    image: any;
    title: any;
    text: any;
    sx?: any;
    landscape?: boolean;
    breakpoint?: number;
  }[];
}) => {
  const handleIsArray = (item: any) => {
    if (Array.isArray(item))
      return item.map((value, index) => (
        <div>
          {index > 0 && <br />}
          <p>{value}</p>
        </div>
      ));
    return item;
  };

  let height: number = 240;


  return (
    <>
      <Padding>
        <Hide on={900}>
          <Zoom delay={100}>
            <div
              style={{
                display: "inline-block",
                height,
                width: "calc(33% - calc(80px / 3))",
                backgroundColor: "",
              }}>
              <ContainerGrowFadeColorOut
                breakpoint={props.items?.[0]?.breakpoint}
                landscape={props.items?.[0]?.landscape}
                img={props.items?.[0].image}
                opacity={props.opacity}></ContainerGrowFadeColorOut>
              <PoppinsFontII
                style={{
                  marginTop: 5,
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[0]?.sx?.desktop?.title,
                }}>
                {props.items?.[0]?.title}
              </PoppinsFontII>
              <PoppinsDarkAndBlueFontTextI
                style={{
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[0]?.sx?.desktop?.subtitle,
                }}>
                {handleIsArray(props.items?.[0]?.text)}
              </PoppinsDarkAndBlueFontTextI>
            </div>
          </Zoom>

          <div
            style={{
              display: "inline-block",
              width: 40,
              height: 300,
              border: "",
            }}
          />
          <Zoom delay={300}>
            <div
              style={{
                display: "inline-block",
                height,
                width: "calc(33% - calc(80px / 3))",
              }}>
              <ContainerGrowFadeColorOut
                breakpoint={props.items?.[1]?.breakpoint}
                landscape={props.items?.[1]?.landscape}
                img={props.items?.[1].image}
                opacity={props.opacity}></ContainerGrowFadeColorOut>
              <PoppinsFontII
                style={{
                  marginTop: 5,
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[1]?.sx?.desktop?.title,
                }}>
                {props.items?.[1]?.title}
              </PoppinsFontII>
              <PoppinsDarkAndBlueFontTextI
                style={{
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[1]?.sx?.desktop?.subtitle,
                }}>
                {handleIsArray(props.items?.[1]?.text)}
              </PoppinsDarkAndBlueFontTextI>
            </div>
          </Zoom>

          <div
            style={{
              display: "inline-block",
              width: 40,
              height: 300,
              border: "",
            }}
          />
          <Zoom delay={500}>
            <div
              style={{
                display: "inline-block",
                height,
                width: "calc(33% - calc(80px / 3))",
              }}>
              <ContainerGrowFadeColorOut
                breakpoint={props.items?.[2]?.breakpoint}
                landscape={props.items?.[2]?.landscape}
                img={props.items?.[2].image}
                opacity={props.opacity}></ContainerGrowFadeColorOut>
              <PoppinsFontII
                style={{
                  marginTop: 5,
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[2]?.sx?.desktop?.title,
                }}>
                {props.items?.[2]?.title}
              </PoppinsFontII>
              <PoppinsDarkAndBlueFontTextI
                style={{
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[2]?.sx?.desktop?.subtitle,
                }}>
                {props.items?.[2]?.text}
              </PoppinsDarkAndBlueFontTextI>
            </div>
          </Zoom>
        </Hide>
        <Hide b4={900}>
          <Zoom delay={100}>
            <div style={{ display: "inline-block", width: 310 }}>
              <ContainerGrowFadeColorOut
                breakpoint={props.items?.[0]?.breakpoint}
                landscape={props.items?.[0]?.landscape}
                height={height}
                img={props.items?.[0].image}
                opacity={props.opacity}></ContainerGrowFadeColorOut>
              <PoppinsFontII
                style={{
                  marginTop: 5,
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[0]?.sx?.mobile?.title,
                }}>
                {props.items?.[0]?.title}
              </PoppinsFontII>
              <PoppinsDarkAndBlueFontTextI
                style={{
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[0]?.sx?.mobile?.subtitle,
                }}>
                {props.items?.[0]?.text}
              </PoppinsDarkAndBlueFontTextI>
            </div>
          </Zoom>
          <SpacerV h={40} />
          <Zoom delay={100}>
            <div style={{ display: "inline-block", width: 310 }}>
              <ContainerGrowFadeColorOut
                breakpoint={props.items?.[1]?.breakpoint}
                landscape={props.items?.[1]?.landscape}
                height={height}
                img={props.items?.[1].image}
                opacity={props.opacity}></ContainerGrowFadeColorOut>
              <PoppinsFontII
                style={{
                  marginTop: 5,
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[1]?.sx?.mobile?.title,
                }}>
                {props.items?.[1]?.title}
              </PoppinsFontII>
              <PoppinsDarkAndBlueFontTextI
                style={{
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[1]?.sx?.mobile?.subtitle,
                }}>
                {props.items?.[1]?.text}
              </PoppinsDarkAndBlueFontTextI>
            </div>
          </Zoom>
          <SpacerV h={40} />
          <Zoom delay={100}>
            <div style={{ display: "inline-block", width: 310 }}>
              <ContainerGrowFadeColorOut
                breakpoint={props.items?.[2]?.breakpoint}
                landscape={props.items?.[2]?.landscape}
                height={height}
                img={props.items?.[2].image}
                opacity={props.opacity}></ContainerGrowFadeColorOut>
              <PoppinsFontII
                style={{
                  marginTop: 5,
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[2]?.sx?.mobile?.title,
                }}>
                {props.items?.[2]?.title}
              </PoppinsFontII>
              <PoppinsDarkAndBlueFontTextI
                style={{
                  fontSize: 14,
                  width: "100%",
                  backgroundColor: "",
                  textAlign: "left",
                  ...props.items?.[2]?.sx?.mobile?.subtitle,
                }}>
                {props.items?.[2]?.text}
              </PoppinsDarkAndBlueFontTextI>
            </div>
          </Zoom>
        </Hide>
      </Padding>
    </>
  );
};

const ContainerGrowFadeColorOut = ({
  children,
  img,
  landscape,
  rgbFragment,
  height,
  breakpoint,
}: any) => (
  <div
    {...css({
      transition: "400ms",
      width: "100%",
      height: height ?? "100%",
      borderRadius: 6,
      backgroundImage: `url(${img ? img : getImagePlaceholder()})`,
      //backgroundSize : landscape ? 'calc(100% + 1px)' : 'auto calc(100% + 1px)',
      backgroundSize: !landscape ? "100%" : "auto 100%",
      backgroundPosition: "center center",
      ...(breakpoint
        ? {
            [on(breakpoint)]: {
              backgroundSize: "auto 100%",
            },
          }
        : {}),
      [onHover]: {
        width: "104%",
        height: "104%",
        marginLeft: "-2%",
        marginTop: "-2%",
      },
    })}>
    <div
      {...css({
        transition: "200ms",
        backgroundColor: rgbFragment
          ? `rgba(${"253, 189, 21"},0.7)`
          : undefined,
        width: "100%",
        height: height ?? "100%",
        color: "white",
        [onHover]: {
          backgroundColor: rgbFragment
            ? `rgba(${rgbFragment},0.25)`
            : undefined,
          //color : 'rgba(253, 189, 21,1.0)',
          ...getDropShadowStyle({}),
        },
      })}>
      {children}
    </div>
  </div>
);
