import React from "react"

const VERSION : string = '1.0.5'

export default ( props : { 
    children : any, 
    nopadding ?: boolean, 
    minHeight ?: number | string, 
    //offsetForMinHeightMargin ?: number, 
    //headerHeight ?: number,
    sx ?: { container ?: any },
    y ?: number, 
    x ?: number,   
}) => {
    const offsetY : number = props.y ? props.y : 0
    const navOffset : number = props.x ? props.x : 0
    return (
        <div style={{ textAlign : 'center', width : `calc(100% - ${navOffset}px)`, ...props?.sx?.container }}>
            <div style={{ marginLeft : navOffset, maxWidth : 1280 - navOffset, width : '100%', minWidth : 350, display : 'inline-block', backgroundColor : ''}}>
                { props.children}
            </div>
        </div>
    )
}

