import React from "react"
import { getChildren } from "../composables/Shared";

export const VERSION : number = 2

export default ( props : { show ?: boolean, children ?: any, gap ?: number, sx ?: { container ?: any } }) => {
    const children: any[] = getChildren( props.children );

    if( props.gap !== undefined ) return (<div style={props?.sx?.container}>
        <div style={{ display: 'inline-block', marginRight : props.gap, ...(props.show ? { backgroundColor : 'red'} : {}) }}>
            {children.length > 0 ? <>{ children[0] }</> : <></>}
        </div>
        <div style={{ display: 'inline-block', ...(props.show ? { backgroundColor : 'purple'} : {}) }}>
            {children.length > 1 ? <>{ children[1] }</> : <></>}
        </div>
        <div style={{ display: 'inline-block', marginLeft : props.gap, ...(props.show ? { backgroundColor : 'blue'} : {}) }}>
            {children.length > 2 ? <>{ children[2] }</> : <></>}
        </div>
    </div>)

    return (<div style={props?.sx?.container}>
        <div style={{ display: 'inline-block', width : `${100/3}%`,...(props.show ? { backgroundColor : 'red'} : {}) }}>
            {children.length > 0 ? <>{ children[0] }</> : <></>}
        </div>
        <div style={{ display: 'inline-block', width : `${100/3}%`,...(props.show ? { backgroundColor : 'purple'} : {}) }}>
            {children.length > 1 ? <>{ children[1] }</> : <></>}
        </div>
        <div style={{ display: 'inline-block', width : `${100/3}%`,...(props.show ? { backgroundColor : 'blue'} : {}) }}>
            {children.length > 2 ? <>{ children[2] }</> : <></>}
        </div>
    </div>)
}