import React from "react"
import DropShadow from "./DropShadow"
import { getFontPoppins } from "../../assets/fonts/FontPoppins"
import { css } from "glamor"
import { on } from "../composables/Hide"
import XY from "../composables/XY"
import { getGradientOrFallbackBackground } from "../shared/shared"

export default ( props : { content ?: any }) => {

    

    let bgc : any = getGradientOrFallbackBackground({
        bgcgradient : props?.content?.sections?.slogan?.bgcgradient,
        bgc : props?.content?.sections?.slogan?.bgc
    })

    const color : string = props?.content?.sections?.slogan?.altText ?? 'white'

    return (
        <DropShadow>
            <div {...css({ height : 60, width : '100%', color,
                ...props.content?.sections?.slogan?.sx?.default,
                ...bgc,
                [on(props.content?.sections?.slogan?.sx?.breakpoint ? props.content.sections.slogan.sx.breakpoint : 600 )]:{ 
                    ...props.content?.sections?.slogan?.sx?.mobile,
                }
            })}>
                <XY>
                    <p style={{ ...getFontPoppins() }}>{ props.content?.sections?.slogan?.value }</p>
                </XY>
            </div>
        </DropShadow>
    )
}