import React from "react"
import { FACEBOOK_BLACK } from "../../../assets/colors/Colors"
import IconFacebook from './header-icon-v1-facebook.svg'
import IconGoogle from './header-icon-v1-google.svg'
import IconInstagram from './header-icon-v1-instagram.svg'
import IconPhone from './header-icon-v1-phone.svg'
import IconYelp from './header-icon-v1-yelp.svg'
import GridRow from "../../../locust/composables/GridRow"
import { getFontPoppins } from "../../../assets/fonts/FontPoppins"
import { getGradientOrFallbackBackground } from "../../../locust/shared/shared"


interface HeaderMiniSocial {
    bgc ?: string, 
    bgcgradient ?: any, 
    color ?: string, 
    phone ?: string,
    facebook ?: string, 
    google ?: string,
    instagram ?: string,
    yelp ?: string,
    phoneNumber ?: {
        label : any, 
        value : string,   
    }, 
}

export default ( props : {
    bgc ?: string, 
    color ?: string, 
    bgcgradient ?: any, 
    phone ?: string,
    facebook ?: string, 
    google ?: string,
    instagram ?: string,
    yelp ?: string,
    phoneNumber ?: {
        label : any, 
        value : string,   
    }, 
}) => <HeaderMiniSocialV1 {...props}/>


export const HeaderMiniSocialV1 = ( props : HeaderMiniSocial ) => {

    let bgc : any = getGradientOrFallbackBackground({
        bgcgradient : props.bgcgradient,
        bgc : props.bgc
    })

    const iconPadding : number = 8
    const iff = ( value : any ) => value !== undefined ? true : false
    const Social = ( props :{ href : string, icon : any }) => <GridRow height={45}><a style={{ padding: iconPadding, backgroundColor : '', float : 'right' }} href={`${props.href}`}><img src={props.icon}/></a> </GridRow>
    const color : string = props.color ? props.color : 'white'

    return (<div style={{ height : 45, ...bgc }}>
        { props.phoneNumber && <GridRow height={45}><a style={{ paddingLeft : 20, float : 'left', color, ...getFontPoppins(), fontWeight : 800, fontSize : 24, textDecoration : 'none'   }} href={`tel:${props.phoneNumber.value}`}> 
            { props?.phoneNumber?.label }
        </a></GridRow>}

        <div style={{ float : 'right', backgroundColor : '', height : '100%', paddingRight : 10 }}>
            { iff(props.phone) && <Social icon={IconPhone} href={`tel:${props.phone}`}/>}
            { iff(props.facebook) && <Social icon={IconFacebook} href={`${props.facebook}`}/>}
            { iff(props.google) && <Social icon={IconGoogle} href={`${props.google}`}/>}
            { iff(props.instagram) && <Social icon={IconInstagram} href={`${props.instagram}`}/>}
            { iff(props.yelp) && <Social icon={IconYelp} href={`${props.yelp}`}/>}
        </div>
    </div>)
}