import React from "react";
import X from '../composables/X'
import Y from '../composables/Y'
import SpacerV from '../composables/SpacerV'
import { css } from 'glamor'

const VERSION : string = '1.0.0'

export const Line = ( props : { padding ?: number, style ?: any  }) => <div style={{ 
        
        height : 1, 
        width : `calc(100% - ${ props.padding ? props.padding : 0 }px)`, 
        backgroundColor : 'rgba(0,0,0,0.05)',
        ...( props.padding ? { marginLeft : props.padding / 2 } : {}),
        ...props?.style,
}}/>


export const LineDivider = ( props : { children ?: any, style ?: Record<string,any> }) => {
        const h : number = 1
        return <X style={{ 
            height : h,
            ...props.style
           }}><div {...css({ 
            height : h, 
            width : 'calc(100% - 50px)',
            maxWidth : 800, 
            backgroundColor : '',
            marginTop : 0,
            ...props.style
        })}>
          <div style={{ width : '100%', height : '100%', backgroundColor : ''}}>
              <Y>
                  <div style={{ width : '100%', backgroundColor : 'rgba(0,0,0,0.1)' , height : 1}}></div>
              </Y>
          </div>
        </div></X>
      
    }
    
    // [UPDATE] changed marginTop/marginBottom to <SpacerV/>
    export const LineDividerSpacer = ( props : { top ?: number, bottom ?: number, style ?: Record<string,any>}) => {
        
        const top : number = props.top ? props.top : 0
        const bottom : number = props.bottom ? props.bottom : 0
        return (
            <>
                <SpacerV h={top}/>
                <div {...css({ 
                    width : '100%', 
                    height : 1, 
                    backgroundColor : 'rgba(0,0,0,0.1)',
                    ...props.style,
                })}/>
                <SpacerV h={bottom}/>
                
            </>
        )
    }