const ContainerGrowFadeColorOutV2 = ({
  noanimate,
  children,
  img,
  landscape,
  rgbFragment,
  height,
  breakpoint,
}: any) => (
  <div
    {...css({
      transition: "400ms",
      width: height ?? 250,
      height: height ?? 250,
      borderRadius: "100%",
      backgroundImage: `url(${img ? img : getImagePlaceholder()})`,
      //backgroundSize : landscape ? 'calc(100% + 1px)' : 'auto calc(100% + 1px)',
      backgroundSize: !landscape ? "100%" : "auto 100%",
      backgroundPosition: "center center",
      ...(breakpoint
        ? {
            [on(breakpoint)]: {
              backgroundSize: "auto 100%",
            },
          }
        : {}),
      [onHover]: noanimate
        ? {}
        : {
            width: "104%",
            height: "104%",
            marginLeft: "-2%",
            marginTop: "-2%",
          },
    })}>
    <div
      {...css({
        transition: "200ms",
        backgroundColor: rgbFragment
          ? `rgba(${"253, 189, 21"},0.7)`
          : undefined,
        width: height ?? 250,
        height: height ?? 250,
        color: "white",
        [onHover]: {
          backgroundColor: rgbFragment
            ? `rgba(${rgbFragment},0.25)`
            : undefined,
          //color : 'rgba(253, 189, 21,1.0)',
          ...getDropShadowStyle({}),
        },
      })}>
      {children}
    </div>
  </div>
);
