import React from "react"
import Hide from "../../../locust/composables/Hide"
import ContainerThirdsV from "../../../locust/containers/ContainerThirdsV"
import { Center } from "../../../locust/composables/Center"
import { ContainerTallBlock } from "./ContainerTallBlock"
import { Fade } from "react-reveal";
import Padding from "../../../locust/composables/Padding"
import { TitleSubtitleAltII } from "../../typography/TypographyBasic"
import { ContainerWideBlock } from "./ContainerWideBlock"
import X from "../../../locust/composables/X"
import SpacerV from "../../../locust/composables/SpacerV"
import { SixServicesBlocks } from "./SixServicesBlocks"

export const getServicesTypeIsVerticalImageBoxWithTextOverlay = ( value : any ) => {
    if( value === undefined ) return true
    if( value.includes('vertical-image-box-with-text-overlay')) return true
    return false
}

export const XServicesBlocks = ( props : { content : any, height ?: number, 
    noshadow ?: boolean, 
}) => Object.keys(props.content.sections.services.items).length === 3 
    ? <ThreeServicesBlocks {...props}/>
    : Object.keys(props.content.sections.services.items).length === 6 
    ? <SixServicesBlocks {...props}/>
    : <QuadServicesBlocks {...props}/>


export const QuadServicesBlocks = ( props : { content : any, height ?: number, 
    noshadow ?: boolean, 
}) => { 


    const height : number | undefined = props.height 
    const allItemsKeys : any[] = Object.keys(props.content.sections.services.items)
    const firstThreeItemKeys : any[] = [
        allItemsKeys[0],
        allItemsKeys[1],
        allItemsKeys[2],
    ]

    const fourthItem : any = props.content.sections.services.items[allItemsKeys[3]]
    const fourthType : any = fourthItem.type ?? { id : 'default' }

    const border : any = '' //1px solid rgba(0,0,0,0.4)
    const nobg : boolean = false
    

    return (
        <>
            <Hide on={980}>
                <ContainerThirdsV gap={20}>
                    { firstThreeItemKeys.map(( keyValue : any, index : number )=>{
                        let item : any = props.content.sections.services.items[ keyValue ]
                        let type : any = props.content.sections.services.items[ keyValue ]?.type ?? { id : 'default' }
                        return (
                            <Fade key={index} bottom delay={(300*index)}>
                                <div style={{ backgroundColor : '', border, borderRadius : 6, overflow : 'hidden' }}>
                                    <ContainerTallBlock type={type} nobg={nobg} noshadow={props.noshadow} src={ item.img } height={height} sx={item?.sx?.desktop}>
                                        <Padding>
                                            <TitleSubtitleAltII  title={<p style={ item?.sx?.desktop?.title }>{ item.title }</p>} subtitle={<>
                                                <p style={{ marginTop : 16 }}>
                                                    {item.valueArray.map(( value : any, index2 : number )=>{
                                                        return <p key={`item-${index}-${index2}`} style={{ marginTop : 16, }}>
                                                            {value}
                                                        </p>  
                                                    })}
                                                </p>
                                            </>}/>
                                        </Padding>
                                    </ContainerTallBlock>
                                </div>
                            </Fade>
                        )
                    })}
                </ContainerThirdsV>
                <SpacerV h={12}/>
                <X>
                    <div style={{ backgroundColor : '', border, width : 940, marginTop : 10, borderRadius : 6 }}>
                        <Fade key={3} bottom delay={300}>
                            <ContainerWideBlock type={fourthType} nobg={nobg} noshadow={props.noshadow} src={ fourthItem.img } height={height}>
                                <Padding>
                                    <TitleSubtitleAltII title={<p style={ fourthItem?.sx?.desktop?.title }>{ fourthItem.title }</p>} subtitle={<>
                                        <p style={{ marginTop : 16 }}>
                                            {fourthItem.valueArray.map(( value : any, index2 : number )=>{
                                                return <p key={`item-${fourthItem}-${index2}`} style={{ marginTop : 16 }}>
                                                    {value}
                                                </p>  
                                            })}
                                        </p>
                                    </>}/>
                                </Padding>
                            </ContainerWideBlock>
                        </Fade>
                    </div>
                </X>
                
                
            </Hide>
            <Hide b4={980}>
                { Object.keys(props.content.sections.services.items).map(( keyValue : any, index : number )=>{
                    let item : any = props.content.sections.services.items[ keyValue ]
                    let type : any = props.content.sections.services.items[ keyValue ]?.type ?? { id : 'default' }
                    return (
                        <Center key={index} >
                            <Fade bottom delay={(300*0)}>
                                <div style={{ backgroundColor : '', border, borderRadius : 6, overflow : 'hidden', marginBottom : 20 }}>
                                    <ContainerTallBlock type={type} nobg={nobg} noshadow={props.noshadow} src={ item.img } height={height} sx={item?.sx?.mobile}>
                                        <Padding>
                                        <TitleSubtitleAltII title={<p style={ item?.sx?.mobile?.title }>{ item.title }</p>} subtitle={<>
                                                <p style={{ marginTop : 16 }}>
                                                    {item.valueArray.map(( value : any, index2 : number )=>{
                                                        return <p key={`item-${index}-${index2}`} style={{ marginTop : 16, fontSize : 14  }}>
                                                            {value}
                                                        </p>  
                                                    })}
                                                </p>
                                            </>}/>
                                        </Padding>
                                    </ContainerTallBlock>
                                </div>
                            </Fade>
                        </Center>
                    )
                })}
            </Hide>
        </>
    )

}


export const ThreeServicesBlocks = ( props : { content : any, height ?: number, 
    noshadow ?: boolean, 
}) => {

    const height : number | undefined = props.height 
    
    const type : string = 'default'
    

    return (
        <>
            <Hide on={980}>
                <ContainerThirdsV gap={20}>
                    { Object.keys(props.content.sections.services.items).map(( keyValue : any, index : number )=>{
                        let item : any = props.content.sections.services.items[ keyValue ]
                        let type : any = props.content.sections.services.items[ keyValue ]?.type ?? { id : 'default' }
                        return (
                            <Fade key={index} bottom delay={(300*index)}>
                                <ContainerTallBlock type={type} noshadow={props.noshadow} src={ item.img } height={height} sx={item?.sx?.desktop}>
                                    <Padding>
                                        <TitleSubtitleAltII title={<p style={ item?.sx?.desktop?.title }>{ item.title }</p>} subtitle={<>
                                            <p style={{ marginTop : 16 }}>
                                                {item.valueArray.map(( value : any, index2 : number )=>{
                                                    return <p key={`item-${index}-${index2}`} style={{ marginTop : 16 }}>
                                                        {value}
                                                    </p>  
                                                })}
                                            </p>
                                        </>}/>
                                    </Padding>
                                </ContainerTallBlock>
                            </Fade>
                        )
                    })}
                </ContainerThirdsV>
            </Hide>
            <Hide b4={980}>
                { Object.keys(props.content.sections.services.items).map(( keyValue : any, index : number )=>{
                    let item : any = props.content.sections.services.items[ keyValue ]
                    let type : any = props.content.sections.services.items[ keyValue ]?.type ?? { id : 'default' }
                    return (
                        <Center key={index} >
                            <Fade bottom delay={(300*0)}>
                                <div style={{ marginBottom : 30 }}>
                                    <ContainerTallBlock type={type} noshadow={props.noshadow} src={ item.img } height={height}  sx={item?.sx?.mobile}>
                                        <Padding>
                                        <TitleSubtitleAltII title={<p style={ item?.sx?.mobile?.title }>{ item.title }</p>} subtitle={<>
                                                <p style={{ marginTop : 16 }}>
                                                    {item.valueArray.map(( value : any, index2 : number )=>{
                                                        return <p key={`item-${index}-${index2}`} style={{ marginTop : 16, fontSize : 14  }}>
                                                            {value}
                                                        </p>  
                                                    })}
                                                </p>
                                            </>}/>
                                        </Padding>
                                    </ContainerTallBlock>
                                </div>
                            </Fade>
                        </Center>
                    )
                })}
            </Hide>
        </>
    )
}

