export const getServicesTypeIsRoundedRectangleWithTitleAndSubtitle = (
  value: any
) => {
  if (value.includes("rounded-rectangles-with-title-and-subtitle")) return true;
  return false;
};

export const getHasAtLeastXServiceItems = (services: any, x: number) => {
  if (!services?.items) return false;
  return Object.keys(services.items).length >= x;
};

export const getServiceItem = (services: any, i: number) => {
  let keyValue = Object.keys(services.items)[i];
  let item = services.items[keyValue];
  return item;
};

export default (props: {
  version?: 1 | 2;
  rgbFragment: string;
  opacity?: number;
  items?: {
    image: any;
    title: any;
    text: any;
    sx?: any;
    landscape?: boolean;
    breakpoint?: number;
  }[];
}) => {
  console.log(props.items);

  return props?.version && props?.version === 2 ? (
    <ThreeServicesITS_V2 {...props} />
  ) : (
    <ThreeServicesITS_V1 {...props} />
  );
};
