import React from "react";
import { getChildren } from "../composables/Shared";

const VERSION : number = 2

export const ContainerSplitPercent = ( props : { show ?: boolean, children : any, gap ?: number, percent : number }) => {
    const children: any[] = getChildren( props.children );
    const gap : number = props.gap !== undefined ? props.gap : 20
    const widthLeft : number | string = `calc(${props.percent}% - ${gap/2}px)`
    const widthRight : number | string = `calc(${100-props.percent}% - ${gap/2}px)`
    
    const childrenLeft : any = children && children.length > 0 ? children[0] : []
    const childrenRight: any = children && children.length > 1 ? children[1] : []
    return (
        <div style={{ width : '100%', textAlign : 'center'}}>
            
            {/* <div style={{ paddingLeft : 20, paddingRight : 20 }}> */}
                <div style={{ verticalAlign : 'top', display : 'inline-block', width :  widthLeft, backgroundColor : props.show ? 'red' : '' }}>
                    { childrenLeft }
                </div>
                <div style={{ verticalAlign : 'top', display : 'inline-block', marginLeft : gap, width :  widthRight, backgroundColor : props.show ? 'blue' : '' }}>
                    { childrenRight }
                </div>

            {/* </div> */}
        </div>
    )
}