import { Box, Button, Dialog, DialogActions, DialogContent, DialogProps, DialogTitle, IconButton } from "@mui/material"
import CloseIcon from '@mui/icons-material/Close';
import React from "react"
import { Popup, PopupButton } from "./Popup";

      export const PopupContainerFullscreen = ( props : {
        title ?: any, 
        popup : Popup, 
        setPopup : ( props : Popup ) => void, 
        buttons : PopupButton[],
        children ?: any
        style ?: Record<string,any>
        above?: boolean,
        onClose ?: () => void 
      }) => {
          
          /*
              NOTE: must put at the very bottom. Otherwise it will not show up on the top of the div stack
              SEE: const example = () => ... (below)
          */
      
        const handleClose = () => {
              setTimeout(()=>{
                  props.setPopup({ ...props.popup, toggle : false });
                  props.onClose && props.onClose()
              }, 200 )
        };
          
        const [maxWidth, setMaxWidth] = React.useState<DialogProps['maxWidth']>('xl');
    
          return (
            
            <React.Fragment>
              <Dialog
                fullWidth={true}
                maxWidth={maxWidth}
                open={props.popup.toggle}
                onClose={handleClose}
              >
                <DialogTitle>
                  { props.title && <div style={{ float : 'left'}}>{ props.title }</div> }
                  <div style={{ float : 'right', cursor : 'pointer'}} onClick={handleClose}><CloseIcon /></div>
                </DialogTitle>
                <DialogContent>
                  
                  {/* <DialogContentText>
                    Some text here
                  </DialogContentText> */}
  
                  <Box noValidate
                      component="form"
                      sx={{
                          display: 'flex',
                          flexDirection: 'column',
                          m: 'auto',
                          width: 'fit-content',
                          height : '100%'
                      }}>
                        <div style={{ width : 'calc(100vw - 120px)', maxWidth : 1480, minHeight : 'calc(100vh - 210px)', backgroundColor : ''}}>
                            { props.popup.children }
                        </div>
                  </Box>
                </DialogContent>
                <DialogActions>
                    { props.buttons.map(( button : PopupButton, index : number )=>{
                        if( button.isHidden !== undefined && button.isHidden() === true ) return <></>
                        return (
                            <Button autoFocus onClick={()=>{
                              if( button.onClick )
                                  button.onClick()
  
                              if( button.closeOnClick )
                                handleClose()
                                
                            }}
                            key={index}
                            >
                                { button.value }
                            </Button>
                        )
                    })}
                </DialogActions>
              </Dialog>
            </React.Fragment>
        );
    }