import React from "react"
import { useEffect, useState } from "react"

const VERSION : number = 3

export const MobileMenuBasic = ( props : { fixed ?: boolean, toggle ?: boolean, children ?: any, top ?: number }) => {

    const [ toggle, setToggle ] = useState( props?.toggle ? props.toggle : false )
    
    useEffect(()=>{
        if(props?.toggle !== undefined) setToggle(props.toggle)
    },[ props?.toggle ])
    
    return (<>
        <div style={{ width : toggle ? 'max(350px,100vw)' : 0, overflow : 'hidden', backgroundColor : 'white', position : props.fixed ? 'fixed' : 'absolute', top : props?.top ?? 115, height : `calc(100vh - ${ 115 - (props as any)?.top ?? 0 }px)`,right : toggle ? 0 : 'min(-100vw,-350px)', transition : '300ms' }}>
            { props.children }
        </div>
    </>)
}   