import { css } from "glamor";
import React from "react";
import { useState } from "react";
import { onHover } from "../../../locust/composables/Shared";
import { on } from "../../../locust/composables/Hide";
import ImageViewer from 'react-simple-image-viewer';

export const PopupGallery = ( props : { 
    items : {
        img : any, 
        invert ?: boolean,
    }[],
    popupGallery ?: {
        buttons ?: any[],
        images ?: any[],
        onClose ?: () => void 
    }
}) => {

    const [ viewerIndex, setViewIndex ] = useState(-1);
    const sizeL     : string = 'calc(calc(calc(100vw - 120px) / 5) - 10px)'
    const sizeXL    : number = 360
    const sizeM     : string = 'calc(calc(calc(100vw - 120px) / 4) - 10px)'
    const sizeS     : string = 'calc(calc(calc(100vw - 120px) / 3) - 10px)'
    const sizeXS    : string = 'calc(calc(calc(100vw - 120px) / 2) - 10px)'

    const onCloseImageViewer = () => setViewIndex(-1)

    const getGalleryStyle = ( index : number ) => {

        //({backgroundSize : (props.items[index] as any).img.style })
        return  (props.items?.[index] as any)?.img?.style?.backgroundSize 
        ? ( props.items[index] as any).img.style 
        : { backgroundSize : '100%'}

    }


    return (
        <>
            <div style={{}}>
                {props.items.map(( item : any, index : number )=>
                    // <Fade bottom delay={ 200 * index }>
                        <div key={index} onClick={()=>setViewIndex(index)} {...css({ 
                            margin: 5, 
                            display : 'inline-block',  
                            backgroundColor : 'white',
                            cursor : 'pointer',
                            backgroundPosition : 'center',
                            backgroundImage : `url(${item.img.url})`,
                            transition : '400ms',
                            [ on(10000) ] : {
                                width : sizeXL, 
                                height : sizeXL, 
                                //backgroundColor : 'blue',
                                
                            },
                            [ on(1600) ] : {
                                width : sizeL, 
                                height : sizeL, 
                                //backgroundColor : 'red',
                              
                            },
                            [ on(700) ] : {
                                width : sizeM, 
                                height : sizeM, 
                                
                                //backgroundColor : 'lime',
                            },
                            [ on(500) ] : {
                                width : sizeS, 
                                height : sizeS, 
                                
                                //backgroundColor : 'purple',
                            },
                            [ on(400) ] : {
                                width : sizeXS, 
                                height : sizeXS, 
                                
                                //backgroundColor : 'pink',
                            },
                            [ onHover ] : {
                                opacity : 0.8, 
                                backgroundSize : item.invert ? 'auto 120%' : '120%',
                            },
                            ...getGalleryStyle( index ),
                            
                        })}/>
                    // </Fade>
                )}
            </div>
            { viewerIndex >= 0 && 
                <>
                    <ImageViewer
                        src={ props.popupGallery && props.popupGallery.images && props.popupGallery.images.map( x => x.url ) as any}
                        currentIndex={ viewerIndex }
                        disableScroll={ false }
                        closeOnClickOutside={ true }
                        onClose={onCloseImageViewer}
                    />
                </>
            }
        </>
    )
}