import React from "react";
import { IoLocationSharp } from "react-icons/io5";
import { FaEnvelope } from "react-icons/fa6";
import { FACEBOOK_BLUE } from "../../../assets/colors/Colors";
import X from "../../../locust/composables/X";
import "./FooterBasic.css";
import { Center } from "../../../locust/composables/Center";

const VERSION: number = 6;

export default (props: {
  version?: 1 | 2;
  items: { title: any; links: { value: any; href: any }[] }[];
  color?: string;
  address?: any;
  contact?: any;
  logo?: any;
  sx?: { logo?: any; container?: any };
}) =>
  props.version && props.version === 2 ? (
    <FooterBasicV2 {...props} />
  ) : (
    <FooterBasicV1 {...props} />
  );

export const FooterBasicV1 = (props: {
  content?: any;
  items: { title: any; links: { value: any; href: any }[] }[];
  color?: string;
  address?: any;
  contact?: any;
  logo?: any;
  sx?: { logo?: any; container?: any; socials?: { emailAnchor?: any } };
}) => {
  const hasContact: boolean = !(
    props?.contact?.includes("undefined") || props?.contact === undefined
  );

  return (
    <div
      className="Footer"
      style={{ ...props.sx?.container }}>
      <div className="Foot1">
        {Object.keys(props.items).map((keyValue: string, index: number) => {
          const item: any = props.items[keyValue as any];
          return (
            <div key={index}>
              <ul>
                <h1>{item.title}</h1>
                {Object.keys(item.links).map(
                  (keyValue2: string, index2: number) => {
                    const asKey: string = keyValue2.toLowerCase();
                    const link: any = item.links[keyValue2];
                    const notALink: boolean = link === false;
                    const LinkElement = (
                      <li key={`${index}-${index2}`}>
                        {notALink ? (
                          <>{keyValue2}</>
                        ) : (
                          <>
                            <a
                              {...{
                                ...(link.href ? { href: link.href } : {}),
                                ...(link.onClick
                                  ? { onClick: link.onClick }
                                  : {}),
                              }}>
                              {keyValue2}
                            </a>
                          </>
                        )}
                      </li>
                    );

                    const alternateName: string = "quote";
                    const variableMenuItemExists: boolean =
                      props.content?.sections?.header?.main?.links?.[asKey] !==
                        undefined ||
                      props.content?.sections?.header?.main?.links?.[
                        alternateName
                      ] !== undefined;

                    if (asKey === "top" || asKey === "services")
                      return LinkElement;
                    else if (variableMenuItemExists) return LinkElement;
                    else return <></>;
                  }
                )}
              </ul>
            </div>
          );
        })}

        <div className="foot-icons">
          {/* {alert(JSON.stringify(props?.sx))}  to check with code is work*/}
          {props.logo && (
            <img
              style={{
                width: 200,
                marginLeft: 0,
                marginRight: 20,
                marginBottom: 20,
                marginTop: -10,
                ...props?.sx?.logo,
              }}
              src={props.logo}
              alt=""
            />
          )}
          <div>
            {props.address && (
              <div style={{ padding: 5 }}>
                <X align="left">
                  <IoLocationSharp />
                  <div
                    style={{
                      color: props.color ? props.color : FACEBOOK_BLUE,
                      fontSize: 14,
                      marginLeft: 10,
                      marginTop: -2,
                    }}>
                    {props.address}
                  </div>
                </X>
              </div>
            )}
            {hasContact && (
              <div style={{ padding: 5 }}>
                <X align="left">
                  <FaEnvelope />

                  <a
                    style={{
                      color: props.color ? props.color : FACEBOOK_BLUE,
                      fontSize: 14,
                      marginLeft: 10,
                      marginTop: -2,
                      ...props?.sx?.socials?.emailAnchor,
                    }}
                    href={props.contact}>
                    {props.contact.replaceAll("mailto:", "")}
                  </a>
                </X>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export const FooterBasicV2 = (props: {
  items: { title: any; links: { value: any; href: any }[] }[];
  color?: string;
  address?: any;
  contact?: any;
  logo?: any;
  sx?: { logo?: any; container?: any; socials?: { emailAnchor?: any } };
}) => {
  const hasContact: boolean = !(
    props?.contact.includes("undefined") || props?.contact === undefined
  );

  return (
    <div
      className="Footer"
      style={{ ...props.sx?.container }}>
      {Object.keys(props.items).length > 1 && (
        <div className="Foot1">
          {Object.keys(props.items).map((keyValue: string, index: number) => {
            const item: any = props.items[keyValue as any];
            return (
              <div key={index}>
                <ul>
                  <h1>{item.title}</h1>
                  {Object.keys(item.links).map(
                    (keyValue2: string, index2: number) => {
                      const link: any = item.links[keyValue2];
                      return (
                        <li key={`${index}-${index2}`}>
                          <a
                            {...{
                              ...(link.href ? { href: link.href } : {}),
                              ...(link.onClick
                                ? { onClick: link.onClick }
                                : {}),
                            }}>
                            {keyValue2}
                          </a>
                        </li>
                      );
                    }
                  )}
                </ul>
              </div>
            );
          })}

          <div className="foot-icons">
            {props.logo && (
              <img
                style={{
                  width: 200,
                  marginLeft: 0,
                  marginRight: 20,
                  marginBottom: 20,
                  marginTop: -10,
                  ...props?.sx?.logo,
                }}
                src={props.logo}
                alt=""
              />
            )}
            <div>
              {props.address && (
                <div style={{ padding: 5 }}>
                  <X align="left">
                    <IoLocationSharp />
                    <div
                      style={{
                        color: props.color ? props.color : FACEBOOK_BLUE,
                        fontSize: 14,
                        marginLeft: 10,
                        marginTop: -2,
                      }}>
                      {props.address}
                    </div>
                  </X>
                </div>
              )}
              {hasContact !== undefined && (
                <div style={{ padding: 5 }}>
                  <X align="left">
                    <FaEnvelope />
                    <a
                      style={{
                        color: props.color ? props.color : FACEBOOK_BLUE,
                        fontSize: 14,
                        marginLeft: 10,
                        marginTop: -2,
                        ...props?.sx?.socials?.emailAnchor,
                      }}
                      href={props.contact}>
                      {props.contact.replaceAll("mailto:", "")}
                    </a>
                  </X>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
      {Object.keys(props.items).length <= 1 && (
        <div
          className="Foot1"
          style={{ width: "100%" }}>
          <Center>
            <Center>
              <img
                src={props.logo}
                style={{ ...props?.sx?.logo }}
                alt=""
              />
            </Center>

            {Object.keys(props.items).map((keyValue: string, index: number) => {
              const item: any = props.items[keyValue as any];
              return (
                <div key={index}>
                  <ul>
                    <Center>
                      <h1>{item.title}</h1>
                    </Center>
                    {Object.keys(item.links).map(
                      (keyValue: string, index2: number) => {
                        const link: any = item.links[keyValue];

                        return (
                          <Center>
                            <li key={`${index}-${index2}`}>
                              <a
                                {...{
                                  ...(link.href ? { href: link.href } : {}),
                                  ...(link.onClick
                                    ? { onClick: link.onClick }
                                    : {}),
                                }}>
                                {keyValue}
                              </a>
                            </li>
                          </Center>
                        );
                      }
                    )}
                  </ul>
                </div>
              );
            })}

            <div className="foot-icons">
              <div>
                {props.address && (
                  <div style={{ padding: 5 }}>
                    <X align="left">
                      <IoLocationSharp />
                      <div
                        style={{
                          color: props.color ? props.color : FACEBOOK_BLUE,
                          fontSize: 14,
                          marginLeft: 10,
                          marginTop: -2,
                        }}>
                        {props.address}
                      </div>
                    </X>
                  </div>
                )}
                {props.contact && (
                  <div style={{ padding: 5 }}>
                    <X align="left">
                      <FaEnvelope />
                      <a
                        style={{
                          color: props.color ? props.color : FACEBOOK_BLUE,
                          fontSize: 14,
                          marginLeft: 10,
                          marginTop: -2,
                        }}
                        href="">
                        {props.contact}
                      </a>
                    </X>
                  </div>
                )}
              </div>
            </div>
          </Center>
        </div>
      )}
    </div>
  );
};
