import { css } from "glamor"
import React from "react"
import { getFontPoppins } from "../../assets/fonts/FontPoppins"
import { on } from "../../locust/composables/Hide"
import Padding from "../../locust/composables/Padding"
import { Center } from "../../locust/composables/Center"
import SpacerV from "../../locust/composables/SpacerV"

export const TitleSubtitleAltLarge = ( props : { center ?: boolean, title : any, subtitle : any, centerElement ?: any  }) => {
    return (
        <div style={{ width : '100%', textAlign : props.center ? 'center' : 'left'}}>
            <div {...css({ fontSize : 56, ...getFontPoppins(), fontWeight : 900, color : 'white',
                [on(600)]: { marginLeft : 0, fontSize : 46, textAlign : 'center' },
                [on(450)]: { fontSize : 40 }  
                })}>{props.title}</div>

            { props.centerElement ? props.centerElement : <></> }
            <Padding>
                <div {...css({ fontSize : 26, ...getFontPoppins(), fontWeight : 100, maxWidth : 500, color : 'white',
                    [on(600)]: { marginLeft : 0, fontSize : 24, textAlign : 'center' },
                    [on(450)]: { fontSize : 20  }  
                })}>{props.subtitle}</div>
            </Padding>
            
        </div>
    )
}


