export const TitleSubtitle = ( props : { color ?: string, center ?: boolean, title : any, subtitle : any, clearstyles ?: boolean, sx ?:{
    title?: any,
    subtitle?:any,
}}) => {
    const basicStylesTitle : any =  {
        ...getFontPoppins(), fontWeight : 100, 
    }
    const basicStylesSubtitle : any =  {
        ...getFontPoppins(), fontWeight : 900,
    }
    return (
        <div style={{ width : '100%', textAlign : props.center ? 'center' : 'left'}}>
            <div {...css( props?.clearstyles ? {  ...basicStylesTitle, ...props?.sx?.title } : { marginLeft : 40, fontSize : 35, ...basicStylesTitle,
                [on(600)]: { marginLeft : 0, fontSize : 30, textAlign : 'center' },
                [on(450)]: { fontSize : 24  },
                ...props?.sx?.title  
            })}>
                    <div style={{ color : props.color ? props.color : undefined }}>
                        {props.title}
                    </div>
            </div>
            <div {...css( props?.clearstyles ? { ...basicStylesSubtitle, ...props?.sx?.subtitle } : { ...basicStylesSubtitle, marginLeft : 40, marginTop : -10, fontSize : 35, 
                [on(600)]: { marginLeft : 0, fontSize : 30, textAlign : 'center' },
                [on(450)]: { fontSize : 24 },
                ...props?.sx?.subtitle  
                })}>
                    <div style={{ color : props.color ? props.color : undefined }}>
                        {props.subtitle}
                    </div>
                </div>
        </div>
    )
}

export const TitleSubtitleAlt = ( props : { color ?: string, space ?: number, center ?: boolean, title : any, subtitle : any, maxWidth ?: number}) => {
    return (
        <div style={{ width : '100%', textAlign : props.center ? 'center' : 'left' }}>
            <Padding>
                <div {...css({ fontSize : 30, textTransform : 'uppercase', ...getFontPoppins(), fontWeight : 900, 
                    [on(600)]: { marginLeft : 0, fontSize : 30, textAlign : 'center' },
                    [on(450)]: { fontSize : 30 }  
                    })}>
                        <div style={{ color : props.color ? props.color : undefined }}>
                            {props.title}
                        </div>
                </div>
                {props.space && <><SpacerV h={props.space}/></>}
                <div style={{ textAlign : props.center ? 'center' : 'left' }}>
                    <div {...css({ display : 'inline-block', fontSize : 20, ...getFontPoppins(), fontWeight : 100, maxWidth : props.maxWidth ? props.maxWidth : 500,
                        [on(600)]: { marginLeft : 0, fontSize : 20, textAlign : 'center' },
                        [on(450)]: { fontSize : 20  }  
                    })}>
                        <div style={{ color : props.color ? props.color : undefined }}>
                            {props.subtitle}
                        </div>
                    </div>
                </div>
            </Padding>
            
            
        </div>
    )
}


