import { css } from "glamor"
import React from "react"
import DropShadow from "../../../locust/components/DropShadow"
import GridRow from "../../../locust/composables/GridRow"
import Container1280 from "../../../locust/containers/Container1280"
import { Button } from "@mui/material"
import { getFontPoppins } from "../../../assets/fonts/FontPoppins"
import { Fade } from "react-reveal";
import SpacerV from "../../../locust/composables/SpacerV"
import { Center } from "../../../locust/composables/Center"
import { getImagePlaceholder } from "../../shared/util"
import { on } from "../../../locust/composables/Hide"
import { TitleSubtitleAltLarge } from "../../typography/TypographyBasic"
import { StackII } from "../../../locust/composables/StackII"
import { onHover } from "../../../locust/composables/Shared"
import XY from "../../../locust/composables/XY"

const VERSION : number = 3

export const LeadWithImageBackground = ( props :{ 
    openLead ?: () => void, 
    img ?: any, 
    content : any, 
    title : string, 
    subtitle : string, 
    buttonText ?: any,
    color ?: string, 
    sx ?: { container ?: any }, 
    breakpoint ?: number, 
}) => {
    
    const height : number = 400
    return (
        <>
        <StackII>
        { true && <>
            <div style={{ height, overflow : 'hidden'}}>
                <div style={{ marginTop : -((height/4)*2), width : 'max(100vw,350px)', height : '100%', background : 'linear-gradient(180deg, black 0%, transparent 100%)'}}>
                    
                </div>
            </div>
            </>
        }

        { true && <>
            <div style={{ height, overflow : 'hidden'}}>
                <div style={{ marginTop : (height/2), width : 'max(100vw,350px)', height : '100%', background : 'linear-gradient(180deg, transparent 0%, black 100%)'}}>
                    
                </div>
            </div>
            </>
        }
        <div {...css({ height : 600, width :'100%', backgroundColor : '', backgroundSize : '100%', backgroundPosition : 'center', backgroundImage : `url(${ props.img ? props.img : getImagePlaceholder()})`, backgroundRepeat : 'no-repeat', [on(props.breakpoint ? props.breakpoint : 550)]:{ backgroundSize : 'cover' },...props?.sx?.container })}>
            <div style={{ width : '100%', height : '100%', backgroundColor : 'rgba(0,0,0,0.4)'}}>
                <Container1280>
                    <GridRow height={600}>
                        <TitleSubtitleAltLarge center title={props.title} subtitle={props.subtitle} centerElement={
                            <div style={{ marginTop : 10, marginBottom: 20, height : 2, width : 100, display : 'inline-block', backgroundColor : 'white'}}/>
                        }/>

                        <DropShadow>
                            <Button onClick={ props.openLead } style={{ border : '2px solid white', backgroundColor : 'transparent', borderRadius : 0, marginTop : 40  }}>
                                <p style={{ ...getFontPoppins(), paddingLeft : 20, paddingRight : 20, color : 'white', fontSize : 14, fontWeight : 500 }}>{ props.buttonText ? props.buttonText : 'Contact Us'}</p>
                            </Button>
                        </DropShadow>
                        <SpacerV h={20}/>
                        <Center>
                            { props.content.social.map(( item : any, index : number )=>{
                                return <a key={index} href={item.href}>
                                    <Fade bottom delay={200 * index}>
                                        <div style={{ width : 44, height : 44, marginLeft : 7, marginRight : 7, display : 'inline-block' }}>
                                            <XY>
                                                <img {...css({ 
                                                    color : props.color ? props.color : 'white', 
                                                    padding: 10, 
                                                    marginTop : 20,
                                                    width : 40,
                                                    transition : '200ms',
                                                    [onHover] : {
                                                        width : 44,
                                                    }
                                                })} src={item.icon}/>
                                            </XY>
                                        </div>
                                    </Fade>
                                </a>
                            })}
                        </Center>
                    </GridRow>
                </Container1280>
            </div>
        </div>
        </StackII>
        </>
    )
}


