import React, { useRef } from "react"
import Hide, { on } from "../../../locust/composables/Hide"
import { onHover } from "../../../locust/composables/Shared"
import { TitleSubtitleAlt, TitleSubtitleAltIII } from "../../typography/TypographyBasic"
import { SR } from "../../../locust/composables/Responsive"
import { Center } from "../../../locust/composables/Center"
import Padding from "../../../locust/composables/Padding"
import { css } from "glamor"
import { getFontPoppins } from "../../../assets/fonts/FontPoppins"
import { Button } from "@mui/material"
import XY from "../../../locust/composables/XY"
import SpacerV from "../../../locust/composables/SpacerV"
import { Fade, Zoom } from "react-reveal";
import DropShadow from "../../../locust/components/DropShadow"
import { LOGS } from "../../../service/logging-service"
import { getGradientOrFallbackBackground } from "../../../locust/shared/shared"
import SolidOrGradientButton from "../../../locust/button-sets/SolidOrGradientButton"

const VERSION : number = 1.2

export const GalleryInline = ( props : {
    openGallery : () => void, 
    openImage : ( index : number ) => void, 
    title ?: string, 
    subtitle ?: string,
    content : any, 
    zoom ?: boolean,
    theme?:any,
    color ?: any
}) => {

    const color : string = props.color ?? 'white'

    const imageStyle : any = {
        width : 200, 
        height : 200, 
        cursor : 'pointer', 
        backgroundColor : 'white', 
        display : 'inline-block', 
        margin : 15, 
        backgroundSize : '100%',
        backgroundPosition : 'center',
        backgroundRepeat : 'no-repeat',
        transition : '400ms',
        [ onHover ] : { backgroundSize : '110%' }
    }

    const on950     : any = { [on(950)]:{ width : 'calc(100% - 30px)', display : 'block' }}
    const on500     : any = { [on(500)]:{ width : 'calc(100% - 30px)', marginTop : 10, marginBottom : 10  }}
    const on500Hide : any = { [on(500)]:{ display : 'none' }}
    const on950Hide : any = { [on(950)]:{ display : 'none' }}
    const getGalleryImage = ( index : number ) => {
        if( index >= props.content.gallery.length && LOGS ) console.log('ERROR: GALLERY LENGTH IS LESS THAN: ' + index )
        if( index >= props.content.gallery.length ) return ''
        return ({ backgroundImage :`url(${ props.content.gallery[index].url })`, backgroundRepeat : 'no-repeat' })
    }

    const getGalleryStyle = ( index : number ) => props.content.gallery[index].style
    //const openImage = ( index : number ) => props.openImage( index )

    const Desktop = () =>  <TitleSubtitleAltIII 
        title={<>
            <p style={{ paddingBottom : 10 }}>
                { props.title ? props.title : <>
                    Our Work
                </>}
            </p>
        </>}
        subtitle={<>
            <p>
                { props.subtitle ? props.subtitle : <>
                    Check out our gallery and discover the superior quality of our outstanding craftsmanship.
                </>}
            </p>
        </>}
    />

    const Mobile = () =>  <TitleSubtitleAlt center 
        title={<>
            <p style={{ paddingBottom : 10 }}>
                { props.title ? props.title : <>
                    Our Work
                </>}
            </p>
        </>}
        subtitle={<>
            <p style={{ textAlign : 'center'}}>
                { props.subtitle ? props.subtitle : <>
                    Check out our gallery and discover the superior quality of our outstanding craftsmanship.
                </>}
            </p>
        </>}
    />

    // fixes effect re-trigger bug that occurs when clicking the gallery button "See More"
    const fx = useRef(true)

    const Effect = ({ children, delay} : any ) => !fx.current ? <>{children}</> : props.zoom ? <Zoom delay={delay ? delay : 0}>{children}</Zoom> : <Fade bottom delay={delay}>{children}</Fade>

    return (
        <>
            <div style={{ backgroundColor : '', width : '100%'}}>
                <SR s1={140} s2={70} breakpoint={550}/>
                <Center>
                    <Hide on={950}>
                        <div {...css({ width : 'max(100vw,340px)', textAlign : 'center', maxWidth : 1000, [on(950)]:{  maxWidth : 800 }})}>
                            <Effect delay={(300*0)}>
                                <div {...css({ ...imageStyle, ...on500, cursor : '', backgroundColor : 'transparent' })}>
                                    <Padding>
                                        <Desktop/>
                                    </Padding>
                                </div>
                            </Effect>
                            <Effect delay={(300*1)}>
                                <div onClick={()=>props.openImage(0)} {...css({ ...getGalleryImage(0), ...imageStyle, ...getGalleryStyle(0), ...on500Hide, backgroundColor : '' })}></div>
                            </Effect>
                            <Effect delay={(300*2)}>
                                <div onClick={()=>props.openImage(1)} {...css({  ...getGalleryImage(1), ...imageStyle, ...getGalleryStyle(1), ...on500Hide })}></div>
                            </Effect>
                            <Effect delay={(300*3)}>
                                <div onClick={()=>props.openImage(2)} {...css({  ...getGalleryImage(2), ...imageStyle, ...getGalleryStyle(2), ...on500Hide})}></div>
                            </Effect>
                            <Effect delay={(300*0)}>
                                <div onClick={()=>props.openImage(3)} {...css({  ...getGalleryImage(3), ...imageStyle, ...getGalleryStyle(3), ...on500 })}></div>
                            </Effect>
                            <Effect delay={(300*1)}>
                                <div onClick={()=>props.openImage(4)} {...css({  ...getGalleryImage(4), ...imageStyle, ...getGalleryStyle(4), ...on500Hide })}></div>
                            </Effect>
                            <Effect delay={(300*2)}>
                                <div onClick={()=>props.openImage(5)} {...css({  ...getGalleryImage(5), ...imageStyle, ...getGalleryStyle(5), ...on500Hide })}></div>
                            </Effect>
                            <Effect delay={(300*3)}>
                                <div onClick={()=>props.openImage(6)} {...css({  ...getGalleryImage(6), ...imageStyle, ...getGalleryStyle(6), ...on500Hide })}></div>
                            </Effect>
                        </div>
                    </Hide>
                 
                    <Hide b4={950} on={500}>
                        <div {...css({ width : 'max(100vw,340px)', textAlign : 'center', maxWidth : 1000, [on(950)]:{  maxWidth : 800 }})}>
                            
                            <Effect>
                                <div {...css({ ...imageStyle, ...on950, ...on500, backgroundColor : 'transparent' })}>
                                    <Mobile/>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(0)} {...css({ ...getGalleryImage(0), ...imageStyle, ...getGalleryStyle(0), ...on500 })}/>
                                    </DropShadow>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(2)} {...css({ ...getGalleryImage(1), ...imageStyle, ...getGalleryStyle(1), ...on500 })}/>
                                    </DropShadow>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(3)} {...css({ ...getGalleryImage(2), ...imageStyle, ...getGalleryStyle(2), ...on500 })}/>
                                    </DropShadow>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(4)} {...css({ ...getGalleryImage(3), ...imageStyle, ...getGalleryStyle(3), ...on500 })}/>
                                    </DropShadow>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(5)} {...css({ ...getGalleryImage(4), ...imageStyle, ...getGalleryStyle(4), ...on500Hide })}/>
                                    </DropShadow>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(6)} {...css({ ...getGalleryImage(5), ...imageStyle, ...getGalleryStyle(5), ...on500Hide })}/>
                                    </DropShadow>
                                </div>
                                <div style={{ display : 'inline-block'}}>
                                    <DropShadow>
                                        <div onClick={()=>props.openImage(7)} {...css({ ...getGalleryImage(6), ...imageStyle, ...getGalleryStyle(6), ...on950Hide })}/>
                                    </DropShadow>
                                </div>
                            </Effect>
                        </div>
                    </Hide>
                  
                    <Hide b4={500}>
                        <div {...css({ width : 'max(100vw,340px)', textAlign : 'center', maxWidth : 1000, [on(950)]:{  maxWidth : 800 }})}>
                            
                            <Effect>
                                <div onClick={()=>props.openImage(0)} {...css({ ...imageStyle, ...on950, ...on500, backgroundColor : 'transparent' })}>
                                    <Mobile/>
                                </div>
                                <DropShadow>
                                    <div onClick={()=>props.openImage(1)} {...css({ ...getGalleryImage(1), ...imageStyle, ...on500 })}/>
                                </DropShadow>
                                <DropShadow>
                                    <div onClick={()=>props.openImage(2)} {...css({ ...getGalleryImage(2), ...imageStyle, ...on500 })}/>
                                </DropShadow>
                                <DropShadow>
                                    <div onClick={()=>props.openImage(3)} {...css({ ...getGalleryImage(3), ...imageStyle, ...on500 })}/>
                                </DropShadow>
                                <DropShadow>
                                    <div onClick={()=>props.openImage(4)} {...css({ ...getGalleryImage(4), ...imageStyle, ...on500 })}/>
                                </DropShadow>
                                <DropShadow>
                                    <div onClick={()=>props.openImage(5)} {...css({ ...getGalleryImage(5), ...imageStyle, ...on500Hide })}/>
                                </DropShadow>
                                <DropShadow>
                                    <div onClick={()=>props.openImage(6)} {...css({ ...getGalleryImage(6), ...imageStyle, ...on500Hide })}/>
                                </DropShadow>
                                {/* <DropShadow>
                                    <div onClick={()=>props.openImage(7)} {...css({ ...getGalleryImage(7), ...imageStyle, ...on950Hide })}/>
                                </DropShadow> */}
                            </Effect>
                        </div>
                    </Hide>
                </Center>
                <SpacerV h={40}/>
                <Center>
                    {/* <SeeGalleryButton onClick={()=>props.openGallery && props.openGallery()}/> */}

                    <SolidOrGradientButton 
                        color={color}
                        onClick={()=>{
                            fx.current = false;
                            props.openGallery && props.openGallery()
                        }}
                        bgc={ props.theme?.bgc ?? undefined }
                        bgcgradient={ props.theme?.bgcgradient ?? undefined }
                        style={{ marginTop : 30 }}>
                                        See More
                    </SolidOrGradientButton>

                </Center>

                <SR s1={140} s2={70} breakpoint={550}/>
            </div>
        
        </>
    )
}

const SeeGalleryButton = ( props : { color ?: string, onClick ?: () => void } ) => {
    return (<Button onClick={props.onClick} style={{ ...getFontPoppins(), textTransform : 'none', backgroundColor : props.color ? props.color : 'black', width : 250, height : 50, borderRadius : 8 }}>
        <XY>
            <p style={{ color : 'white'}}>
                See More
            </p>
        </XY>
    </Button>)
}