import { onHover } from "../locust/composables/Shared"

export const getImagePlaceholder = () => 'https://firebasestorage.googleapis.com/v0/b/locust-labs-d87f6.appspot.com/o/product-images%2Fimage-placeholder-ii.jpeg?alt=media'
export const landscapeStyle : any = { backgroundSize : 'auto 100%', [ onHover ] : { backgroundSize : 'auto 120%' }}
export const formatPhone = ( phone : string ) => phone.replaceAll(" ", "+")
export const extendFooterLink = ( props : { content : any, column : String, id : String, extension : any }) => ({
    ...( props.content.sections.footer.items[ (props as any ).column].links?.[ (props as any).id ] ? {
        [(props as any).id] : props.extension,
    } : {}),
})






