export const getRandomString = (length?: number) => {
    length = length ? length : 10;
    var result = '';
    var characters =
        'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    var charactersLength = characters.length;
    for (var i = 0; i < length; i++) {
        result += characters.charAt(
            Math.floor(Math.random() * charactersLength)
        );
    }
    return result;
};

export const capitalize = ( str : string ) => {
    if( !str || str.length <= 1 ) return str
    return (str.substring(0,1).toUpperCase()) + (str.substring(1, str.length))
}

export const capitalizeEach = ( str : string ) => {
    if(!str) return str
    let strTrimmed : string = trimSafe(str)
    if( strTrimmed.length <= 1 ) return capitalize(str)
    let splitStr = strTrimmed.split(' ')
    if(splitStr.length < 2) return capitalize(str)
    splitStr = splitStr.map(( x )=>capitalize(x))
    return splitStr.join(' ')
}

