export const getEmpty = (n: number) => {
    const nodes: ReactNode[] = [];
    while (n-- > 0) nodes.push(<></>);
    return nodes;
};

export const getEmptyObject = (n: number) => {
    let nodes: any = {}
    while (n-- > 0) 
    nodes = {
        ...nodes,
        [n] : {}
    }
    return nodes;
};

