import { css } from "glamor"
import React from "react"

const VERSION : number = 2

export default ( props : { onClick ?: () => void, height ?: number | string, align ?: 'top'|'middle'|'bottom', children ?: any, bgc ?: string, style ?: any  }) => {
    return <div onClick={props.onClick} {...css({ display : 'inline-block', width : 'auto', backgroundColor : props.bgc ? props.bgc : '', ...props.style})}>
        <div style={{ display : 'table-cell', height : props.height ? props.height : 30, verticalAlign : props.align ? props.align : 'middle'}}>
            {props.children}
        </div>
    </div>
}