import { css } from 'glamor';
import React, { Component } from 'react';

const VERSION : string = '1.0.0'

export default class SpacerV extends Component<{ h: number; c?: string, children ?: any  }> {
    render() {
        return (
            <div
                {...css({
                    height: this.props.h,
                    width: '100%',
                    backgroundColor: this.props.c ? this.props.c : 'transparent'
                })}
            >{this.props.children}</div>
        );
    }
}


export class SpacerH extends Component<{ w: number; c?: string, children ?: any  }> {
    render() {
        return (
            <div
                {...css({
                    height: '100%',
                    display : 'inline-block',
                    width: this.props.w,
                    backgroundColor: this.props.c ? this.props.c : 'transparent'
                })}
            >{this.props.children}</div>
        );
    }
}
