export const getGradientOrFallbackBackground = (props : { 
    bgcgradient ?: {
        color : any[] | string,
        angle ?: number
    },
    bgc ?: string, 
}) => {

    return ( props?.bgcgradient?.color ? {
        // this allows a gradient to be inferred by two colors in an array, 
        // or be overriden via a gradient string value
        // ie. something like linear-gradient(180deg, whitesmoke 0%, transparent 100%)
        background : typeof props.bgcgradient.color === 'string' 
        ? props.bgcgradient.color
        : (props.bgcgradient.color as any[]).length > 1 
        ? `linear-gradient(${ props.bgcgradient?.angle? props.bgcgradient.angle : 90}deg, ${props.bgcgradient.color[0] } 0%, ${props.bgcgradient.color[1]} 100%)`
        : FACEBOOK_BLACK
    } : props?.bgc ? {
        backgroundColor : props.bgc
    } : { 
        backgroundColor : FACEBOOK_BLACK
    })
}

export const getRandomString = (length?: number) => {
    length = length ? length : 10;
    var result = '';
    var characters =
        'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    var charactersLength = characters.length;
    for (var i = 0; i < length; i++) {
        result += characters.charAt(
            Math.floor(Math.random() * charactersLength)
        );
    }
    return result;
};

export const isNumber = ( value : any) => !(!/^\d+(\.\d+)?/.exec(value)) && String(value).length - String(value).replaceAll('.','').length <= 1
  
export const isEqualStr = ( str1 : string, str2 : string ) => {
    //console.log('starting: ' + str1 + ' ' + str2)
    let a : string, b : string;
    for( let i = 0 ; i < str1.length; i++){
        a = str1.charAt(i)
        b = str2.charAt(i)
        if(a !== b) return false
        //console.log(`${a} === ${b} : ${a === b}`)
    }
    return true
}

export const removeInnerObject = ( props : { object : any, removeByKey : string  }) => {
    let updatedObject = {}
    Object.keys( props.object ).forEach(( keyValue : string )=>{
        if( keyValue !== props.removeByKey ) updatedObject = {
            ...updatedObject, 
            [ keyValue ] : props.object[ keyValue ]

        }
    })
    return updatedObject
}

export const getStringIdLast36 = ( src : string ) => src.substring( src.length-36, src.length )

export const getStringMap = ( array : any[] ) => {
    let map : any = {}
    array.forEach(( value : string )=>{
        map = {
            ...map,
            [getStringIdLast36(value)] : value
        }
    },[])
    return map
}

export const isModified = ( value1 : string, value2 : string ) => !(value1.indexOf( value2 ) !== -1 && value2.indexOf(value1) !== -1)

export const getXuple = ( items : string[], x : number  ) => {

    let xuplesUpdate : any = []
    let buffer : any[] = []

    for( let i = 0, counter = 0; i < items.length; i++, counter++ ){
        if( counter >= x ){
            counter = 0;
            xuplesUpdate.push(buffer)
            buffer = []
        }
        buffer.push( items[i] )
    }
    if( buffer.length > 0 ) xuplesUpdate.push(buffer)

    return xuplesUpdate
}


export function hexToRgb(hex: string): { r: number; g: number; b: number } | null {
    // Check if the provided hex string is valid
    const isValidHex = /^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$/.test(hex);
    if (!isValidHex) {
      console.error('Invalid hex color format');
      return null;
    }
  
    // Remove '#' from the beginning (if present)
    const cleanedHex = hex.replace('#', '');
  
    // Parse the hex values into RGB components
    let r: number, g: number, b: number;
    if (cleanedHex.length === 3) {
      // Convert short hex format (e.g., "#RGB") to full format (e.g., "#RRGGBB")
      r = parseInt(cleanedHex.charAt(0) + cleanedHex.charAt(0), 16);
      g = parseInt(cleanedHex.charAt(1) + cleanedHex.charAt(1), 16);
      b = parseInt(cleanedHex.charAt(2) + cleanedHex.charAt(2), 16);
    } else {
      // Convert full hex format (e.g., "#RRGGBB") directly
      r = parseInt(cleanedHex.substr(0, 2), 16);
      g = parseInt(cleanedHex.substr(2, 2), 16);
      b = parseInt(cleanedHex.substr(4, 2), 16);
    }
  
    // Return the RGB values
    return { r, g, b };
  }
  