export const getPoppinsDarkAndBlueTextStyle = () => ({
    ...getFontPoppins(),
    fontWeight : 500,
    textDecoration : 'none',
    verticalAlign : 'top',
    letterSpacing : 1.15,
    fontSize : 12, 
    textTransform : 'none', 
})

export const PoppinsDarkAndBlueFontTextI = (props : {
    children ?: any,
    style ?: any,  
}) => {
    const style : any = {
        ...getFontMontserrat(), 
        fontSize : 15, 
        fontWeight : 400,
        color : MIDNIGHT_BLUE,
        ...props.style
    }
   
    return <div style={style}>{ props.children}</div>   
}


export const PoppinsDarkAndBlueFontPrice = (props : {
    children ?: any,
    style ?: any,  
    noformat ?: boolean, 
    noseo ?: boolean    
}) => {
    const style : any = {
        ...getFontPoppins(),
        color : FACEBOOK_BLUE,
        fontWeight : 300, 
        WebkitTextStroke : '1.5px ' + + (props?.style?.color ? props.style.color : FACEBOOK_BLUE),  
        letterSpacing : 0,
        paddingTop :props.noformat ? 0 :  7.5, 
        paddingBottom : props.noformat ? 0 : 7.5, 
        fontSize : 22, 
    }
    const Text = () => (props.noseo 
        ? <div style={style}>{ props.children}</div> 
        : <h1 style={style}>{ props.children}</h1>
    )
    return <Text/>    
}

