export const TitleText = ( props : { c ?: string, children ?: any, style ?: Record<string,any>}) => {
    const SubtitleIIStyle = {
        ...getFontMontserrat(),
        fontWeight : 500,
        color : props.c ? props.c : MIDNIGHT_BLUE,
        fontSize : 12,
        ...props.style    
    }
    return <div style={{ display : 'inline-block', width : '100%', ...SubtitleIIStyle }}>
        {props.children}
    </div>
}


export const TitleSection =  ( props : { nobar ?: boolean, color ?: string, title : string | ReactNode, children ?: any, barStyle ?: any  }) => {
    return (<>

        <SpacerV h={80}/>
        { !props.nobar && <>
            <div style={{ width : '100%', textAlign : 'center'}}>
                <div style={{ display : 'inline-block', height : 10, backgroundColor : props.color ? props.color : 'black', ...props.barStyle}}/>
            </div>
        </>}
        <SpacerV h={15}/>

        <div style={{ width : '100%', textAlign : 'center'}}>
            <div style={{ display : 'inline-block', textAlign : 'center', marginLeft : 0, verticalAlign : 'top', backgroundColor : '', height : 40, marginTop : 0 }}>
            <div style={{ ...getFontRaleway(), whiteSpace : 'nowrap',  fontSize : 60 }}>
                        
                    { props.title }
                    
                </div>
            </div>
        </div>
        <SpacerV h={50}/>
        <div style={{ width : '100%', textAlign : 'center'}}>
            <div style={{ ...getFontRaleway(), display : 'inline-block', fontWeight : 500, fontSize : 20, textAlign : 'center', color : 'rgba(0,0,0,0.8)'}}>
                { props.children } 
                
            </div>
        </div>
        <SpacerV h={70}/>    
    </>)


}