import React from "react"
import DropShadow from "../../../locust/components/DropShadow"
import { getImagePlaceholder } from "../../shared/util"
import XY from "../../../locust/composables/XY"
import Padding from "../../../locust/composables/Padding"

const VERSION : number = 2.1

export const ContainerWideBlock = ( props : {
    src ?: any 
    children ?: any, 
    height ?: number,
    noshadow ?: boolean, 
    nobg ?: boolean,
    type ?: any,
    sx ?: { container ?: any } 
}) => {

    if( props?.type?.id === 'simple') return (
        <>
            <DropShadow none={props.noshadow ? true : false }>
                <div style={{ 
                        
                        height : (props.height ? props.height : 550), 
                        width : 'calc(100% - 60px)',
                        border :  props?.type?.color ? `1px solid ${props.type.color}` : `1px solid black`,
                        //backgroundColor : 'whitesmoke',
                        //backgroundImage : props.nobg ? undefined : `url(${ props.src ? props.src : getImagePlaceholder()})`,
                        //backgroundRepeat : 'no-repeat',
                        //backgroundSize : 'cover',
                        //backgroundPosition : 'center',
                        ...props?.sx?.container
                    }}>
                        <Padding>
                            { props.children }
                        </Padding>
                </div>
            </DropShadow>
        
        </>
    )
    return (
        <DropShadow none={props.noshadow ? true : false }>
            <div style={{ 
                    //marginBottom : 20, 
                    width : 'calc(100% - 60px)', 
                    height : '100%', 
                    padding: 30, 
                    //backgroundColor : 'whitesmoke',
                    backgroundImage : props.nobg ? undefined : `url(${ props.src ? props.src : getImagePlaceholder()})`,
                    backgroundRepeat : 'no-repeat',
                    backgroundSize : 'cover',
                    backgroundPosition : 'center'
                }}>
                <XY>
                    <DropShadow none={props.noshadow ? true : false }>
                        <div style={{ 
                            width : '100%', 
                            height : '100%', 

                            backgroundColor : 'rgba(255,255,255,0.8)'
                        }}>
                            { props.children }
                        </div>
                    </DropShadow>
                </XY>
            </div>
        </DropShadow>
    )
}



