import React from "react"
import Hide from "../../locust/composables/Hide"
import Padding from "../../locust/composables/Padding"
import { FACEBOOK_BLUE } from "../../assets/colors/Colors"
import GridRow from "../../locust/composables/GridRow"
import { Center } from "../../locust/composables/Center"
import { getFontPoppins } from "../../assets/fonts/FontPoppins"
import { Fade } from "react-reveal";
import XY from "../../locust/composables/XY"
import { getGradientOrFallbackBackground } from "../../locust/shared/shared"
import X from "../../locust/composables/X"

const VERSION : number = 1

export const RectangleIconTitleSubtitle = ( props : { color ?: string, title : any, subtitle : any, fade ?: number | boolean, icon ?: any, theme ?: any }) => {
    let fade : number | undefined = props.fade !== undefined && typeof props.fade === 'boolean' ? 200 : props.fade 
    if( props.fade === undefined ) return <RectangleIconTitleSubtitleV1 {...props}/>
    else return <RectangleIconTitleSubtitleV2 {...{...props, fade }}/>
}

export const RectangleIconTitleSubtitleV1 = ( props : { color ?: string, title : any, subtitle : any, icon ?: any, theme ?: any  }) => {

    const defaultBg : any = { 
        backgroundColor : props.color ? props.color : FACEBOOK_BLUE
    }

    let bulletColorOverride : any = props.theme?.bulletColor ? {
        backgroundColor : props.theme?.bulletColor
    } : undefined

    let bgc : any = bulletColorOverride !== undefined ? bulletColorOverride : props.theme ? getGradientOrFallbackBackground({
        bgcgradient : props.theme?.bgcgradient,
        bgc : props.theme?.bgc
    }) : defaultBg 


    return (
        <>
            <Hide on={600}>
                <div style={{ width : 250, height : 70, backgroundColor : '', display : 'inline-block'}}>               
                    <div style={{ width : 70, height : 70, display : 'inline-block', borderRadius : '100%', ...bgc }}>
                        <XY> { props.icon } </XY>
                    </div>
                    <div style={{ width : 'calc(100% - 70px)', height : 70, display : 'inline-block' }}>
                        <div style={{ paddingLeft : 10, textAlign : 'left', ...getFontPoppins(), fontWeight : 800, fontSize : 14 }}>{ props.title}</div>
                        <div style={{ paddingLeft : 10, paddingTop : 5, textAlign : 'left', ...getFontPoppins(), fontSize : 12,  }}>{ props.subtitle}</div>
                    </div>
                </div>
            </Hide>
            <Hide b4={600}>
                <div style={{ width : 310, backgroundColor : '', height : 75, marginBottom : 40  }}>
                    <div style={{ width : 70, height : 70, display : 'inline-block', borderRadius : '100%', ...bgc }}>
                        <XY> { props.icon } </XY>
                    </div>
                    <div style={{ width : 'calc(100% - 70px)', height : 70, display : 'inline-block', backgroundColor : '' }}>
                        <Padding p={0} l={20} r={0}>
                        <div style={{ paddingLeft : 10, textAlign : 'left', ...getFontPoppins(), fontWeight : 800, fontSize : 14 }}>{ props.title}</div>
                    <div style={{ paddingLeft : 10, paddingTop : 5, textAlign : 'left', ...getFontPoppins(), fontSize : 12  }}>{ props.subtitle}</div>
                        </Padding>
                    </div>
                </div>
            </Hide>
        </>
    )
}

