import { Button } from "@mui/material";
import { FACEBOOK_BLACK } from "../../assets/colors/Colors"
import { getFontPoppins } from "../../assets/fonts/FontPoppins"
import XY from "../composables/XY"
import React from "react";
import { getGradientOrFallbackBackground } from "../shared/shared";

export default ( props : { 
    children ?: any, 
    bgc ?: any, 
    bgcgradient ?: any, 
    color ?: string, 
    onClick ?: () => void, style ?: any  
}) => {

    let bgc : any = getGradientOrFallbackBackground({
        bgcgradient : props.bgcgradient,
        bgc : props.bgc
    })

    const color : string = props.color ?? 'white'

    return (<Button 
        onClick={props.onClick} 
        style={{ 
            ...getFontPoppins(), 
            textTransform : 'none', 
            width : 250, 
            height : 50, 
            borderRadius : 8, 
            ...props.style,
            ...bgc,
        }}>
        <XY>
            <p style={{ color }}>
                {props.children}
            </p>
        </XY>
    </Button>)
}