import { Helmet } from "react-helmet"
import React, { useEffect, useRef, useState } from "react"
import { motion } from "framer-motion"
import { GlobalStyleWithMinimumScroll } from "../../styles/GlobalStyle"
import { PopupContainerFullscreen } from "../components/PopupFullScreen"
import { PopupV1 } from "../popups/types"
import ImageViewer from 'react-simple-image-viewer';
import Hide, { on } from "./Hide"
import { css } from "glamor"
import { ContainerSplitPercent } from "../containers/ContainerSplitPercent"
import { Button, TextField } from "@mui/material"
import Padding from "./Padding"
import { getFontPoppins } from "../../assets/fonts/FontPoppins"
import { ContainerSplitL } from "../containers/ContainerSplit"
import { Fade } from "react-reveal";
import { Center } from "./Center"
import SpacerV from "./SpacerV"
import { PopupGallery } from "../../library/galleries/PopupGallery/PopupGallery"
import { navigate } from "gatsby"
import XY from "./XY"

const VERSION : number = 5
const initialProps : any = {
    initial : { opacity : 0 }, animate : { opacity : 1}, transition : { delay : 0.5, duration : 0.5 }
}

export default ( props : {
    version ?: 1 | 2, 
    children ?: any,
    title ?: string,
    description ?: string, 
    content ?: any, 
    popupGallery ?: {
        title ?: any, 
        buttons ?: any[],
        images ?: any[],
        toggle ?: boolean
        imageIndex ?: number, 
        onClose ?: () => void,
    },
    popupLead ?: {
        email : string, 
        title ?: any, 
        buttons ?: any[],
        toggle ?: boolean
        onClose ?: () => void,
        placeholders ?:{
            email ?: string, 
            phone ?: string, 
            message ?: string, 
        } 
    },
    mobileMenu ?: any  
}) => {
    
    const [ imageIndex,  setImageIndex   ] = useState( -1 )
    const [ pageProps,  setPageProps    ] = useState( initialProps )
    const [ loaded,     setLoaded       ] = useState( false )
    const [ pageTitle,  setPageTitle    ] = useState( props.title ? props.title : "" )
    const [ pageDesc,   setPageDesc     ] = useState( props.description ?  props.description : "" )
    const [ pageURL,    setPageURL      ] = useState<any>()
    const [ popupGallery, setPopupGallery ] = useState<PopupV1>({ toggle : false })
    const [ popupLead, setPopupLead ] = useState<PopupV1>({ toggle : false })


    const onCloseGallery = () => {
        props.popupGallery && props.popupGallery.onClose && props.popupGallery.onClose()
    }

    const onCloseLeads = () => {
        props.popupLead && props.popupLead.onClose && props.popupLead.onClose()
    }


    useEffect(()=>{
        ( async()=>{
            //if( window && window.location.href.includes('?'))
            //if( window && !window.location.href.includes('test=true'))
                //await getGPSAndSubmitWiseguysQRScan({ id : 'anonymous'})
        })()
    },[])


    useEffect(()=>{
        setPageURL( window.location.href )
        setLoaded( true )
    },[])

    useEffect(()=>{
        ( async()=>{
            if( props?.popupGallery?.toggle ) setPopupGallery({ 
                toggle : true, 
                children : <>
                    {(props.popupGallery && props.popupGallery.images) && 
                        <PopupGallery
                            items={
                                props.popupGallery && props.popupGallery.images && props.popupGallery.images.map(( item : any )=>({
                                    img : item
                            }))}
                            popupGallery={{
                                ...props.popupGallery,
                            }}
                        />
                    }
                    
                </> 
            })
            else onCloseGallery()
        })()

    },[ props?.popupGallery?.toggle])


    useEffect(()=>{
        if( props?.popupGallery?.imageIndex !== undefined ) setImageIndex( props.popupGallery.imageIndex )
    },[ props?.popupGallery?.imageIndex ])

    useEffect(()=>{
        ( async()=>{
            if( props?.popupLead?.toggle ) setPopupLead({ 
                toggle : true, 
                children : <>
                    <Lead 
                        version={props.version}
                        email={props.popupLead?.email ? props.popupLead.email : ""} 
                        title={props.popupLead?.title ? props.popupLead.title : "Me"} 
                        company={props.popupLead.title } 
                        content={props.content}
                        placeholders={ props?.popupLead?.placeholders ? props.popupLead.placeholders : undefined } 
                    />
                </> 
            })
            else onCloseLeads()
        })()

    },[ props?.popupLead?.toggle])

    const popupGalleryButtons : any[] = props.popupGallery && props.popupGallery.buttons ? props.popupGallery.buttons : [
        { value : 'Close', closeOnClick : true, onClick : () => { 
            if( props.popupGallery && props.popupGallery.onClose )
                props.popupGallery.onClose()
        }},
    ]

    const popupLeadButtons : any[] = props.popupLead && props.popupLead.buttons ? props.popupLead.buttons : [
        // { value : 'Close', closeOnClick : true, onClick : () => { 
        //     if( props.popupLead && props.popupLead.onClose )
        //         props.popupLead.onClose()
        // }},
    ]

    if( !loaded ) return <></>

    return (
      <>
       <Helmet>
            <title>{pageTitle}</title>
            <meta property="og:title" content={pageTitle}/>
            <meta name="twitter:title" content={pageTitle}/>
            <meta name="description" content={pageDesc}/>
            <meta property="og:description" content={pageDesc}/>
            <meta name="twitter:description" content={pageDesc}/>
            <meta property="og:url" content={pageURL}/> 
            
            {/* 
                <meta name="twitter:card" content="summary_large_image"/>
                <meta name="image" content={socialShareFree}/>
                <meta property="og:image" content={socialShareFree}/>
                <meta name="twitter:image" content={socialShareFree}/> 
            */}

        </Helmet>
        <GlobalStyleWithMinimumScroll/>
        <motion.div {...pageProps}>
            { props.children}
        </motion.div>
        
        <PopupContainerFullscreen   
            title={ props?.popupGallery?.title ? props.popupGallery.title : undefined }
            popup={popupGallery} 
            setPopup={setPopupGallery}
            buttons={ popupGalleryButtons }
            onClose={ onCloseGallery }
        />

        <PopupContainerFullscreen   
            title={ props?.popupLead?.title ? props.popupLead.title : undefined }
            popup={popupLead} 
            setPopup={setPopupLead}
            buttons={ popupLeadButtons }
            onClose={ onCloseLeads }
        />

         { imageIndex >= 0 && 
            <>
                <ImageViewer
                    src={ props.popupGallery && props.popupGallery.images && props.popupGallery.images.map( x => x.url ) as any}
                    currentIndex={ imageIndex }
                    disableScroll={ false }
                    closeOnClickOutside={ true }
                    onClose={()=>setImageIndex(-1)}
                />
            </>
        }
        
        { props.mobileMenu && <>{ props.mobileMenu }</>}

      </>
    );
};

const Lead = ( props : {
    version ?: 1 | 2, 
    company : any, 
    content : any, 
    title : string, 
    email : string,
    placeholders ?:{
        email ?: string, 
        phone ?: string, 
        message ?: string, 
    } 
}) => props.version && props.version === 2 ? <LeadV2 {...props}/> : <LeadV1 {...props}/>


const LeadV1 = ( props : {
    company : any, 
    content : any, 
    title : string, 
    email : string,
    placeholders ?:{
        email ?: string, 
        phone ?: string, 
        message ?: string, 
    } 
}) => {

    
    const ContactPoint = ( props : { label : any, value : any, icon ?: any }) =>  <div style={{ marginTop : 20, marginBottom : 20 }}>
        { props.icon 
            ? <ContainerSplitL widthLeft={30}>
                <div style={{ display : 'inline-block', backgroundColor : 'whitesmoke', width : 30, height : 30, borderRadius : '100%' }}/>
                <div style={{ width : '100%', textAlign : 'left', marginTop : - 3}}>
                    <div style={{ display : 'inline-block', marginLeft : 10, ...getFontPoppins(), fontSize : 16, fontWeight : 600, textTransform : 'uppercase' }}>
                        <p>{ props.label }</p>
                        <p>{ props.value }</p>
                    </div>
                </div>
            </ContainerSplitL>
            : <div style={{ width : '100%', textAlign : 'left', marginTop : - 3}}>
                <div style={{ display : 'inline-block', marginLeft : 10, ...getFontPoppins(), fontSize : 16, fontWeight : 600, textTransform : 'uppercase' }}>
                    <p>{ props.label }</p>
                    <p>{ props.value }</p>
                </div>
            </div>
        }

    </div>

    const LeftTop = () => <div style={{ textAlign : 'left'}}>
        <div style={{ ...getFontPoppins(), fontSize : 30, fontWeight : 600 }}>Contact Details</div>
        { props.content.sections.lead.contacts.map(( item : any )=>{
            return <ContactPoint label={item.label} value={item.value} icon={item.icon} />
        })}
        
        {/* <ContactPoint label="Email" value="(817) 793-4134" icon={<></>}/> */}
        {/* <ContactPoint label="Address" value="7611 W Mossy Cup St Boise, ID 83709"/> */}
        
        { props.content.sections.contact.social.length > 0 && <ContactPoint label="Social" value="" icon={props.content.sections.lead.socials.icon}/> }
        <div style={{ marginTop : -40, marginLeft : 0 }}>
            { props.content.sections.lead.socials.links.map(( item : any, index : number )=>{
                return <a key={index} href={item.href}><Fade bottom delay={200 * index}><img style={{  padding: 10, marginTop : 20  }} src={item.icon}/></Fade></a>
            })}
        </div>

    </div>

    const RightBottom = ( propsII : {
        placeholders ?:{
            email ?: string, 
            phone ?: string, 
            message ?: string, 
        }
    }) => {

        const phone = useRef('')
        const name = useRef('')
        const message = useRef('')


        return (
            <div style={{ textAlign : 'left' }}>                   
                <div style={{ ...getFontPoppins(), fontSize : 30, fontWeight : 600 }}>Request a Quote</div>
                    
                
                <ContactPoint label="Email" value=""/>
                <div {...css({ marginTop : -20, width : 'calc(100% - 20px)', marginLeft : 14, marginBottom : 30, [on(700)]:{
                    width : '100%'

                } })}>
                    <TextField 
                        placeholder={ propsII?.placeholders?.phone ? propsII.placeholders.phone : undefined }
                        onChange={( event )=>{
                            let updatedValue = event.target.value;
                            (name as any).current = updatedValue;
                        }}
                        fullWidth 
                        id="standard-basic" 
                        variant="standard" 
                    />
                </div>
                
                <ContactPoint label="Phone" value=""/>
                <div {...css({ marginTop : -20, width : 'calc(100% - 20px)', marginLeft : 14, marginBottom : 30, [on(700)]:{
                    width : '100%'

                } })}>
                    <TextField 
                        placeholder={ propsII?.placeholders?.phone ? propsII.placeholders.phone : undefined }
                        onChange={( event )=>{
                            let updatedValue = event.target.value;
                            (phone as any).current = updatedValue;
                        }}
                        fullWidth 
                        id="standard-basic" 
                        variant="standard" 
                    />
                </div>

                <ContactPoint label="Message" value=""/>
                <div {...css({ marginTop : -10, width : 'calc(100% - 20px)', marginLeft : 10, marginBottom : 30, [on(700)]:{
                    width : '100%'

                }})}>
                    <TextField 
                        placeholder={ propsII?.placeholders?.message ? propsII.placeholders.message : undefined }
                        onChange={( event )=>{
                            let updatedValue = event.target.value;
                            (message as any).current = updatedValue;
                        }}
                        multiline 
                        rows={4} 
                        fullWidth 
                        id="standard-basic" 
                        variant="outlined" 
                        style={{  }}
                    />
                </div>
                
                <div style={{ ...getFontPoppins(), fontSize : 10, marginTop : -8, color : 'rgba(0,0,0,0.6)'}}>
                    By providing { props.company } your contact information, you acknowledge and agree to our Privacy Policy and consent to receiving marketing communications, including through automated calls, texts, and emails, some of which may use artificial or prerecorded voices. This consent isn't necessary for purchasing any products or services and you may opt out at any time. To opt out from texts, you can reply, 'stop' at any time. To opt out from emails, you can click on the unsubscribe link in the emails. Message and data rates may apply.
                </div>
                <Center>
                    <Button onClick={()=>navigate(`mailto:${props.email}?subject=Question%20for%20${props.title.replaceAll(" ","%20")}&body=Customer%20Name:%20${name.current}%20%0D%0A%20Customer%20Number:%20${phone.current}%20%0D%0A%20%0D%0A%20${message.current}`)} style={{ ...getFontPoppins(), marginTop : 30, width : 200, height : 50, fontSize : 14, fontWeight : 800, color : 'black', border : '2px solid black', borderRadius : 0, }}>Submit</Button>
                </Center>
            </div>
        )
    }

    return (
        <>  
            <Hide on={700}>
                <ContainerSplitPercent gap={0} percent={50}>
                    <>
                        <Padding l={0}>
                            <LeftTop/>
                        </Padding>
                    </>
                    <>
                        <Padding r={0}>
                            <RightBottom {...props}/>
                        </Padding>
                    </>
                </ContainerSplitPercent>
                <div style={{ left : '50%', position : 'absolute', width : 1, height : '100%', top : 0, backgroundColor : 'rgba(0,0,0,0.3)' }}></div>
            </Hide>
            <Hide b4={700}>
                <div style={{ maxWidth : 350 }}>
                    <Padding l={0}>
                        <LeftTop/>
                        <SpacerV h={80}/>
                        <RightBottom {...props}/>
                    </Padding>
                </div>
            </Hide>
        </>
    )
}


