import React from "react"
import Hide, { on } from "../../../locust/composables/Hide"
import Padding from "../../../locust/composables/Padding"
import { SR } from "../../../locust/composables/Responsive"
import { getImagePlaceholder } from "../../shared/util"
import { ContainerSplitL } from "../../../locust/containers/ContainerSplit"
import XY from "../../../locust/composables/XY"
import { Center } from "../../../locust/composables/Center"
import { FiveStarGFYRsp } from "../../../locust/social-media/reviews/FiveStarGFY"
import GridRow from "../../../locust/composables/GridRow"
import SpacerV from "../../../locust/composables/SpacerV"
import { TitleSubtitleAltIII } from "../../typography/TypographyBasic"
import { css } from "glamor"
import DropShadow from "../../../locust/components/DropShadow"
import { Fade } from "react-reveal";
import { StackII } from "../../../locust/composables/StackII"

const version : number = 1.2
export const AboutBasicBusiness = ( props : { 
    content : any, 
    nobg ?: boolean, 
    noreviews?: boolean,
    breakpoint ?: number,
    sx ?: {
        img ?: {
            mobile ?: any,
            desktop ?: any,
        },
        title ?: {
            mobile ?: any, 
        },
        subtitle ?: {
            mobile ?: any, 
        }
    }
}) => {
    
    let breakpoint : number = props?.breakpoint ?? 550
    return (
        <>
            <Hide on={900}>        
                <SR s1={140} s2={0} breakpoint={breakpoint}/>
                <Padding p={0} l={40} r={40}>
                    <ContainerSplitL gap={0} widthLeft={450}>
                        <>
                            <XY>
                                <Fade delay={300}>
                                    <DropShadow>
                                        <div style={{ 
                                            width : 425,
                                            height : 300, 
                                            borderRadius : 10,
                                            backgroundImage : `url(${ props.content.img ? props.content.img : getImagePlaceholder() })`,
                                            backgroundSize : 'cover',
                                            backgroundPosition : 'center',
                                            backgroundRepeat : 'no-repeat',
                                            ...props?.sx?.img?.desktop

                                        }}></div>
                                    </DropShadow>
                                </Fade>
                            </XY>
                        </>
                        <>
                            <Center>
                                <div style={{ maxWidth : 500 }}>
                                    <Padding t={0} b={0}>                                                 
                                        <TitleSubtitleAltIII 
                                            title={<>
                                                <p style={{ paddingBottom : 20 }}>
                                                    { props.content.title }
                                                </p>
                                            </>}
                                            subtitle={<>
                                                { props.content.valueArray.map(( item : any, index : number )=>{
                                                    return <p key={index} style={{ paddingBottom : 20}}>
                                                        {item}
                                                    </p>
                                                })}
                                                <SpacerV h={20}/>
                                            
                                            </>}
                                        />
                                        <Center>
                                            <FiveStarGFYRsp 
                                                gap={10}
                                                breakpoint={950}
                                                facebook={props.content.facebook}
                                                yelp={props.content.yelp}
                                                google={props.content.google}
                                            />
                                        </Center>
                                    </Padding>
                                </div>
                            </Center>
                        </>

                    </ContainerSplitL>
                </Padding>
                <SR s1={140} s2={70} breakpoint={breakpoint}/>
            </Hide>
            <Hide b4={ 900 }>
                <StackII>
              
                        
                    <div {...css({ 
                        height : 700, 
                        width :'100%', 
                        backgroundColor : '', 
                        backgroundSize : '120% auto', 
                        backgroundPosition : 'center',
                        backgroundImage : props.noreviews ? undefined : props.nobg ? undefined : `url(${ props.content.img ? props.content.img : getImagePlaceholder() })`, 
                        backgroundRepeat : 'no-repeat', 
                        [on(breakpoint)]:{ backgroundSize : 'auto 120%' },
                        ...props?.sx?.img?.mobile
                    
                    })}>
                        
                    </div>
                    { !props.nobg && 
                        <div style={{ height : 700, overflow : 'hidden'}}>
                            <div style={{ marginTop : -((600/3)), width : '100vw', height : '100%', background : 'linear-gradient(180deg, black 0%, transparent 100%)'}}>
                                
                            </div>
                        </div>
                    }

                    { !props.nobg && 
                        <div style={{ height : 700, overflow : 'hidden'}}>
                            <div style={{ marginTop : (600/3), width : '100vw', height : '100%', background : 'linear-gradient(180deg, transparent 0%, black 100%)'}}>
                                
                            </div>
                        </div>
                    }

                    <Center>
                            <div {...css({ maxWidth : 380, [on(400)]:{ maxWidth : 330 }})}>
                                <GridRow height={600}>        
                                    <TitleSubtitleAltIII 
                                        title={<>
                                            <p style={{ paddingBottom : 20, fontSize : 20, color : 'white', ...props?.sx?.title?.mobile  }}>
                                                { props.content.title }
                                            </p>
                                        </>}
                                        subtitle={<>
                                            { props.content.valueArray.map(( item : any, index : number )=>{
                                                return <p key={`mobile-${index}`} style={{ paddingBottom : 24, color : 'white', ...props?.sx?.title?.mobile  }}>
                                                    {item}
                                                </p>
                                            })}
                                            <SpacerV h={20}/>
                                        
                                        </>}
                                    />
                                
                                    <Center>
                                        <FiveStarGFYRsp 
                                            gap={10}
                                            breakpoint={950}
                                            facebook={props.content.facebook}
                                            yelp={props.content.yelp}
                                            google={props.content.google}
                                        />
                                    </Center>
                                </GridRow>
                            </div>
                        </Center>

                    
                </StackII>
            </Hide>
            
        
        </>
    )
}


