const VERSION : number = 3.1

export default ( props : {
    mobile ?: boolean, 
    content : any, 
    logo ?: any, 
    //links : { href ?: string, onClick ?: ()=> void }[], 
    links : any, 
    nav ?: any, 
    sx ?: { 
        linkContainer ?: any, 
        logo ?: any, 
        icon ?: { desktop ?: any, mobile ?: any }, 
        text ?: { desktop ?: any, mobile ?: any },
        container ?: { desktop ?: any, mobile ?: any }, 
    } 
    services ?: {
        value : any,
        space : number, 
        onClick ?: () => void,
    },
    mobileMenu ?: {
        icon ?: any, 
        onClick : () => void   
    }
}) => <HeaderServiceAreaQuoteV1 {...props}/>

export const HeaderServiceAreaQuoteV1 = ( props : {
    mobile ?: boolean, 
    content : any, 
    logo ?: any, 
    nav ?: any, 
    //links : { href ?: string, onClick ?: ()=> void }[], 
    links : any, 
    sx ?: { 
        linkContainer ?: any, 
        logo ?: any,
        icon ?: { desktop ?: any, mobile ?: any }, 
        text ?: { desktop ?: any, mobile ?: any },
        container ?: { desktop ?: any, mobile ?: any }, 
    } 
    services ?: {
        value : any,
        space : number, 
        onClick ?: () => void,
    },
    mobileMenu ?: {
        icon ?: any, 
        onClick : () => void   
    }
}) => {
    const space : number = 20
    const height : number = 70
    const [ links, setLinks ] = useState( props.content.links )

    console.log( props?.sx )

    useEffect(()=>{
        let updatedLinks : any = { ...props.content.links }

        Object.keys(updatedLinks).forEach(( keyValue : string )=>{ 
            
            if( props?.nav?.[keyValue]?.onClick !== undefined )
                updatedLinks = { ...updatedLinks,
                
                [ keyValue ] : {
                    ...updatedLinks[keyValue],
                    onClick : props.nav[keyValue].onClick
                }
            }
        })
         setLinks( updatedLinks )
    },[])

    

    if( props.mobile ) return <div>
        <Line/>

        { links?.quote?.onClick && 
            <GridRow onClick={links?.quote?.onClick } height={ height } style={{ cursor : 'pointer', width : '100%', backgroundColor : '', transition : '200ms',[onHover] : { backgroundColor : 'whitesmoke' }}}>
                <Padding t={0} b={0}>    
                    <IconSAQ sx={{ icon : { marginLeft : -8,  marginRight : 6 }}} icon={ Quote } title={links?.quote?.title} subtitle={links?.quote?.subtitle }/>
                </Padding>
            </GridRow>
        }  

        { links?.area?.onClick && 
            <GridRow height={ height } style={{ width : '100%', backgroundColor : '', transition : '200ms',[onHover] : { backgroundColor : 'whitesmoke' }}}>
                <Padding t={0} b={0}>    
                    <IconSAQ sx={{ icon : { marginRight : 10  } }} icon={ Area } title={links?.area?.title} subtitle={links?.area?.subtitle }/>
                </Padding>
            </GridRow>
        }
        
        { links?.services?.onClick && 
            <GridRow onClick={links?.services?.onClick } height={ height } style={{ cursor : 'pointer', width : '100%', backgroundColor : '', transition : '200ms',[onHover] : { backgroundColor : 'whitesmoke' }}}>
                <Padding t={0} b={0}>
                    <IconSAQ sx={{ icon : { marginLeft : -4, marginRight : 4 }}} icon={ Service } title={links?.services?.title} subtitle={links?.services?.subtitle }/>
                </Padding>
            </GridRow>
        }


        { links?.gallery?.onClick &&
            <GridRow onClick={ links?.gallery?.onClick } height={ height } style={{ cursor : 'pointer', width : '100%', backgroundColor : '', transition : '200ms',[onHover] : { backgroundColor : 'whitesmoke' }}}>
                <Padding t={0} b={0}>    
                    <IconSAQ sx={{ icon : {  marginLeft : -3, marginRight : 6 }, img : { height : 34 }}} icon={ Gallery } title={links?.gallery?.title} subtitle={links?.gallery?.subtitle }/>
                </Padding>
            </GridRow>
        }
         
        
    </div>

    

    return (
        <div style={{ height : height, backgroundColor : 'white', width : '100%', ...props?.sx?.container?.desktop }}> 
            <Hide on={850}>
                { props.logo && 
                    <GridRow height={ height } {...css({ float : 'left',cursor : 'pointer' })}>
                        
                        <img src={props.logo} style={{ marginLeft : 10, ...props?.sx?.logo }} height={ props?.sx?.logo?.height ? props.sx.logo.height : undefined } width={ props?.sx?.logo?.width ? props.sx.logo.width : 200 } />
                    </GridRow>
                }

                { links?.quote?.onClick && 
                    <GridRow  onClick={links?.quote?.onClick } height={height} style={{ float : 'right', marginRight : 16, cursor : 'pointer', ...props?.sx?.text?.desktop  }}>
                        <IconSAQ sx={{ icon : props?.sx?.icon?.desktop }} w={ 120 + space } icon={ Quote } title={links?.quote?.title} subtitle={links?.quote?.subtitle }/>
                    </GridRow>
                }  
                
                { links?.area?.onClick && 
                    <GridRow onClick={links?.area?.onClick } height={height} style={{ float : 'right', ...props?.sx?.text?.desktop  }}>
                        <IconSAQ sx={{ icon : { marginRight : 10, ...props?.sx?.icon?.desktop  } }} w={ 140 + space } icon={ Area } title={links?.area?.title} subtitle={links?.area?.subtitle }/>
                    </GridRow>
                }
                
                { links?.services?.onClick && 
                    <GridRow onClick={links?.services?.onClick } height={height} style={{ float : 'right',cursor : 'pointer', ...props?.sx?.text?.desktop  }}>
                        <IconSAQ sx={{ img : { marginTop : -3, ...props?.sx?.icon?.desktop }, icon : { marginRight : 4, }}} w={ 160 + space } icon={ Service } title={links?.services?.title} subtitle={links?.services?.subtitle }/>
                    </GridRow>
                }

                { links?.gallery?.onClick && 
                    <GridRow onClick={links?.gallery?.onClick } height={height} style={{ float : 'right',cursor : 'pointer', marginRight : 25, ...props?.sx?.text?.desktop   }}>
                        <IconSAQ sx={{ img : { marginTop : -3, ...props?.sx?.icon?.desktop }, icon : { marginRight : 4, }}} w={ 100 + space } icon={ Gallery } title={links?.gallery?.title} subtitle={links?.gallery?.subtitle }/>
                    </GridRow>
                }

            </Hide>
            <Hide b4={850}>
                <div style={{ maxHeight : height, overflow : 'hidden'}}>
                    <GridRow height={height} style={{ float : 'left', cursor : 'pointer' }}>
                        <img src={props.logo} style={{ marginLeft : 10, ...props?.sx?.logo }} height={ props?.sx?.logo?.height ? props.sx.logo.height : undefined } width={props?.sx?.logo?.width ? props.sx.logo.width : 150 } />
                    </GridRow>
                    <GridRow height={height} style={{ float : 'right', marginRight : 16, cursor : 'pointer'  }}>
                        {props?.mobileMenu?.icon ? <>{props.mobileMenu.icon}</> : <Menu onClick={ props.mobileMenu?.onClick } {...css({ width : 30, color : 'black', cursor : 'pointer', [onHover] : { color : 'rgba(0,0,0,0.75)' }})}/>}    
                    </GridRow>
                </div>
            </Hide>
        </div>
    )
}

