export const IconSAQ = ( props : {
    icon ?: any,
    height ?: number, 
    title ?: string, 
    subtitle ?: string, 
    w ?: number,
    sx ?: { icon ?: any, img ?: any }
}) => {

    const show : boolean = false
    const height : number = props.height ? props.height : 50

    return <>
        
        <div style={{ display : 'inline-block', width : props.w }}>
            <X align="left">
                <div style={{ display : 'inline-block', height, ...props?.sx?.icon }}>
                    <GridRow height={height}>
                        <img src={ props.icon } style={ props?.sx?.img }/>
                    </GridRow>
                </div>
                <div style={{ display : 'inline-block', height, ...getFontMontserrat(), textTransform : 'uppercase' }}>
                    <div style={{ display : 'inline-block', height : height/2, width : '100%', fontWeight : 600, fontSize : 12, backgroundColor : !show ? '' : 'red' }}>
                        <GridRow align="bottom" height={height/2}>{props.title}</GridRow>
                    </div>
                    <div style={{ display : 'inline-block', height : height/2, width : '100%', fontWeight : 400, fontSize : 9, backgroundColor :  !show ? '' : 'blue' }}>
                        <GridRow align="top" height={height/2}>{props.subtitle}</GridRow>
                    </div>
                </div>
            </X>
        </div>
        
        
        
    </>
}